  1→use anyhow::Result;
  2→use async_trait::async_trait;
  3→use tokio_util::sync::CancellationToken;
  4→
  5→use crate::bus::SharedBus;
  6→
  7→// =============================================================================
  8→// Startable - Uniform adapter lifecycle trait
  9→// =============================================================================
 10→
 11→/// Trait for adapters that can be started/stopped uniformly.
 12→/// This enables the coordinator to manage all adapters through a single codepath.
 13→#[async_trait]
 14→pub trait Startable: Send + Sync {
 15→    /// Adapter name/prefix (e.g., "lms", "openhome")
 16→    fn name(&self) -> &'static str;
 17→
 18→    /// Start the adapter. No-op if already running or can't start.
 19→    async fn start(&self) -> Result<()>;
 20→
 21→    /// Stop the adapter gracefully.
 22→    async fn stop(&self);
 23→
 24→    /// Whether this adapter can be started (e.g., has required config).
 25→    /// Default: true (most adapters can always start).
 26→    async fn can_start(&self) -> bool {
 27→        true
 28→    }
 29→}
 30→
 31→/// Macro to implement Startable trait with minimal boilerplate.
 32→///
 33→/// Adapters must implement:
 34→/// - `async fn start_internal(&self) -> Result<()>`
 35→/// - `async fn stop_internal(&self)`
 36→/// - Optionally: custom `can_start` method (pass as third arg)
 37→///
 38→/// Usage:
 39→/// ```ignore
 40→/// impl_startable!(OpenHomeAdapter, "openhome");
 41→/// impl_startable!(LmsAdapter, "lms", is_configured);  // custom can_start
 42→/// ```
 43→#[macro_export]
 44→macro_rules! impl_startable {
 45→    // With custom can_start method
 46→    ($adapter:ty, $name:literal, $can_start:ident) => {
 47→        #[async_trait::async_trait]
 48→        impl $crate::adapters::Startable for $adapter {
 49→            fn name(&self) -> &'static str {
 50→                $name
 51→            }
 52→
 53→            async fn start(&self) -> anyhow::Result<()> {
 54→                self.start_internal().await
 55→            }
 56→
 57→            async fn stop(&self) {
 58→                self.stop_internal().await
 59→            }
 60→
 61→            async fn can_start(&self) -> bool {
 62→                self.$can_start().await
 63→            }
 64→        }
 65→    };
 66→    // Default can_start (always true)
 67→    ($adapter:ty, $name:literal) => {
 68→        #[async_trait::async_trait]
 69→        impl $crate::adapters::Startable for $adapter {
 70→            fn name(&self) -> &'static str {
 71→                $name
 72→            }
 73→
 74→            async fn start(&self) -> anyhow::Result<()> {
 75→                self.start_internal().await
 76→            }
 77→
 78→            async fn stop(&self) {
 79→                self.stop_internal().await
 80→            }
 81→        }
 82→    };
 83→}
 84→
 85→/// Context passed to adapter logic during execution
 86→pub struct AdapterContext {
 87→    /// Event bus for publishing events
 88→    pub bus: SharedBus,
 89→    /// Cancellation token for shutdown coordination
 90→    pub shutdown: CancellationToken,
 91→}
 92→
 93→/// Command that can be sent to an adapter
 94→#[derive(Debug, Clone)]
 95→pub enum AdapterCommand {
 96→    Play,
 97→    Pause,
 98→    PlayPause,
 99→    Stop,
100→    Next,
101→    Previous,
102→    VolumeAbsolute(i32),
103→    VolumeRelative(i32),
104→    Mute(bool),
105→}
106→
107→/// Response from command execution
108→#[derive(Debug, Clone)]
109→pub struct AdapterCommandResponse {
110→    pub success: bool,
111→    pub error: Option<String>,
112→}
113→
114→/// Adapter-specific logic trait
115→///
116→/// Implementors provide discovery and protocol handling.
117→/// Lifecycle (startup, shutdown, ACK) is handled by AdapterHandle.
118→#[async_trait]
119→pub trait AdapterLogic: Send + Sync + 'static {
120→    /// Unique prefix for zone IDs (e.g., "lms", "roon", "openhome")
121→    fn prefix(&self) -> &'static str;
122→
123→    /// Run the adapter's main loop (discovery, polling, etc.)
124→    /// Should publish ZoneDiscovered/Updated/Removed events to ctx.bus
125→    /// Returns when ctx.shutdown is triggered or on error
126→    async fn run(&self, ctx: AdapterContext) -> Result<()>;
127→
128→    /// Handle a command for a zone owned by this adapter
129→    /// Called by AdapterHandle when a matching command arrives
130→    async fn handle_command(
131→        &self,
132→        zone_id: &str,
133→        command: AdapterCommand,
134→    ) -> Result<AdapterCommandResponse>;
135→
136→    /// Optional: called before run() for one-time setup
137→    async fn init(&self) -> Result<()> {
138→        Ok(())
139→    }
140→}
