  1→//! Volume control component with support for different volume types.
  2→//!
  3→//! Handles:
  4→//! - "db": dB scale with suffix
  5→//! - "number": 0-100 numeric scale
  6→//! - "incremental": blind control (+/- only, no value)
  7→//! - Fixed volume: hides controls entirely
  8→
  9→use dioxus::prelude::*;
 10→
 11→/// Volume type enum for cleaner pattern matching
 12→#[derive(Clone, Copy, PartialEq)]
 13→pub enum VolumeType {
 14→    /// dB scale (typically negative values, 0 is max)
 15→    Db,
 16→    /// Numeric scale (typically 0-100)
 17→    Number,
 18→    /// Incremental/blind control (no absolute value)
 19→    Incremental,
 20→    /// Fixed volume (no control available)
 21→    Fixed,
 22→}
 23→
 24→impl VolumeType {
 25→    /// Parse volume type from API response
 26→    pub fn from_api(volume: Option<f32>, volume_type: Option<&str>) -> Self {
 27→        match (volume, volume_type) {
 28→            // Explicit "fixed" type from API
 29→            (_, Some("fixed")) => VolumeType::Fixed,
 30→            // Legacy: no volume means fixed
 31→            (None, _) => VolumeType::Fixed,
 32→            (Some(_), Some("db")) => VolumeType::Db,
 33→            (Some(_), Some("incremental")) => VolumeType::Incremental,
 34→            (Some(_), _) => VolumeType::Number, // Default to number for "number" or unknown
 35→        }
 36→    }
 37→}
 38→
 39→/// Format volume for display, showing decimals only when step is fractional
 40→fn format_volume(volume: f32, step: Option<f32>, suffix: &str) -> String {
 41→    // Show decimals if step is fractional (not a whole number)
 42→    let show_decimal = step.map(|s| s.fract() != 0.0).unwrap_or(false);
 43→    if show_decimal {
 44→        format!("{:.1}{}", volume, suffix)
 45→    } else {
 46→        format!("{}{}", volume.round() as i32, suffix)
 47→    }
 48→}
 49→
 50→/// Compact volume controls for zone cards
 51→#[component]
 52→pub fn VolumeControlsCompact(
 53→    volume: Option<f32>,
 54→    volume_type: Option<String>,
 55→    volume_step: Option<f32>,
 56→    on_vol_down: EventHandler<()>,
 57→    on_vol_up: EventHandler<()>,
 58→) -> Element {
 59→    let vol_type = VolumeType::from_api(volume, volume_type.as_deref());
 60→
 61→    // Don't render anything for fixed volume
 62→    if vol_type == VolumeType::Fixed {
 63→        return rsx! {};
 64→    }
 65→
 66→    let volume_display = match vol_type {
 67→        VolumeType::Db => volume
 68→            .map(|v| format_volume(v, volume_step, " dB"))
 69→            .unwrap_or_default(),
 70→        VolumeType::Number => volume
 71→            .map(|v| format_volume(v, volume_step, ""))
 72→            .unwrap_or_default(),
 73→        VolumeType::Incremental | VolumeType::Fixed => String::new(),
 74→    };
 75→
 76→    rsx! {
 77→        div { class: "ml-auto flex items-center gap-1",
 78→            button {
 79→                class: "btn btn-outline btn-sm",
 80→                onclick: move |_| on_vol_down.call(()),
 81→                "−"
 82→            }
 83→            if vol_type != VolumeType::Incremental {
 84→                span { class: "min-w-[3.5rem] text-center text-sm",
 85→                    "{volume_display}"
 86→                }
 87→            }
 88→            button {
 89→                class: "btn btn-outline btn-sm",
 90→                onclick: move |_| on_vol_up.call(()),
 91→                "+"
 92→            }
 93→        }
 94→    }
 95→}
 96→
 97→/// Full volume controls with label for zone detail view
 98→#[component]
 99→pub fn VolumeControlsFull(
100→    volume: Option<f32>,
101→    volume_type: Option<String>,
102→    volume_step: Option<f32>,
103→    on_vol_down: EventHandler<()>,
104→    on_vol_up: EventHandler<()>,
105→) -> Element {
106→    let vol_type = VolumeType::from_api(volume, volume_type.as_deref());
107→
108→    // Don't render anything for fixed volume
109→    if vol_type == VolumeType::Fixed {
110→        return rsx! {};
111→    }
112→
113→    let volume_display = match vol_type {
114→        VolumeType::Db => volume
115→            .map(|v| format_volume(v, volume_step, " dB"))
116→            .unwrap_or_default(),
117→        VolumeType::Number => volume
118→            .map(|v| format_volume(v, volume_step, ""))
119→            .unwrap_or_default(),
120→        VolumeType::Incremental | VolumeType::Fixed => String::new(),
121→    };
122→
123→    rsx! {
124→        if vol_type != VolumeType::Incremental {
125→            span { style: "margin-left:1rem;", "Volume: ", strong { "{volume_display}" } }
126→        } else {
127→            span { style: "margin-left:1rem;", "Volume:" }
128→        }
129→        button {
130→            style: "width:2.5rem;",
131→            onclick: move |_| on_vol_down.call(()),
132→            "−"
133→        }
134→        button {
135→            style: "width:2.5rem;",
136→            onclick: move |_| on_vol_up.call(()),
137→            "+"
138→        }
139→    }
140→}
