  1→//! AdapterCoordinator - Centralized lifecycle management for adapters
  2→//!
  3→//! The coordinator serves as a registry of all available adapters and manages their lifecycle.
  4→//! It tracks which adapters are enabled and handles starting/stopping them uniformly.
  5→
  6→use std::collections::HashMap;
  7→use std::time::Duration;
  8→
  9→use anyhow::Result;
 10→use tokio::sync::RwLock;
 11→use tokio::task::JoinHandle;
 12→use tokio_util::sync::CancellationToken;
 13→use tracing::{debug, error, info, warn};
 14→
 15→use crate::adapters::Startable;
 16→use crate::api::AdapterSettings;
 17→use crate::bus::{BusEvent, SharedBus};
 18→use std::sync::Arc;
 19→
 20→/// All available adapters in the system.
 21→/// This is the single source of truth for what adapters exist.
 22→/// Note: "lms-cli" is a companion to "lms" and shares its enabled state.
 23→pub const AVAILABLE_ADAPTERS: &[&str] = &["roon", "lms", "lms-cli", "openhome", "upnp"];
 24→
 25→/// Registered adapter with its spawn function
 26→struct RegisteredAdapter {
 27→    /// Adapter prefix (e.g., "lms", "roon")
 28→    #[allow(dead_code)]
 29→    prefix: String,
 30→    /// Whether this adapter is currently enabled
 31→    enabled: bool,
 32→    /// Running task handle (if started)
 33→    handle: Option<JoinHandle<()>>,
 34→    /// Cancellation token for this adapter
 35→    cancel: CancellationToken,
 36→}
 37→
 38→/// AdapterCoordinator manages adapter lifecycle:
 39→/// - Register adapters by prefix
 40→/// - Start only enabled adapters
 41→/// - Coordinate graceful shutdown
 42→pub struct AdapterCoordinator {
 43→    adapters: RwLock<HashMap<String, RegisteredAdapter>>,
 44→    bus: SharedBus,
 45→    /// Global shutdown token (parent of all adapter tokens)
 46→    shutdown: CancellationToken,
 47→    /// Timeout for shutdown acknowledgments
 48→    shutdown_timeout: Duration,
 49→}
 50→
 51→impl AdapterCoordinator {
 52→    pub fn new(bus: SharedBus) -> Self {
 53→        Self {
 54→            adapters: RwLock::new(HashMap::new()),
 55→            bus,
 56→            shutdown: CancellationToken::new(),
 57→            shutdown_timeout: Duration::from_secs(5),
 58→        }
 59→    }
 60→
 61→    /// Create with custom shutdown timeout
 62→    pub fn with_shutdown_timeout(bus: SharedBus, timeout: Duration) -> Self {
 63→        Self {
 64→            adapters: RwLock::new(HashMap::new()),
 65→            bus,
 66→            shutdown: CancellationToken::new(),
 67→            shutdown_timeout: timeout,
 68→        }
 69→    }
 70→
 71→    /// Register all available adapters using settings to determine enabled state.
 72→    /// This is the primary way to initialize the coordinator.
 73→    pub async fn register_from_settings(&self, settings: &AdapterSettings) {
 74→        for &name in AVAILABLE_ADAPTERS {
 75→            let enabled = match name {
 76→                "roon" => settings.roon,
 77→                "lms" => settings.lms,
 78→                // lms-cli shares enabled state with lms (companion adapter)
 79→                "lms-cli" => settings.lms,
 80→                "openhome" => settings.openhome,
 81→                "upnp" => settings.upnp,
 82→                _ => false,
 83→            };
 84→            self.register(name, enabled).await;
 85→            if enabled {
 86→                info!("Adapter {} enabled", name);
 87→            } else {
 88→                info!("Adapter {} disabled", name);
 89→            }
 90→        }
 91→    }
 92→
 93→    /// Start all enabled adapters from the provided list.
 94→    /// This is the single codepath for starting adapters.
 95→    pub async fn start_all_enabled(&self, adapters: &[Arc<dyn Startable>]) {
 96→        for adapter in adapters {
 97→            let name = adapter.name();
 98→            if !self.is_enabled(name).await {
 99→                debug!("Adapter {} is disabled, skipping", name);
100→                continue;
101→            }
102→            if !adapter.can_start().await {
103→                debug!("Adapter {} cannot start (not configured?), skipping", name);
104→                continue;
105→            }
106→            match adapter.start().await {
107→                Ok(()) => info!("Started adapter: {}", name),
108→                Err(e) => warn!("Failed to start adapter {}: {}", name, e),
109→            }
110→        }
111→    }
112→
113→    /// Stop all adapters from the provided list.
114→    pub async fn stop_all(&self, adapters: &[Arc<dyn Startable>]) {
115→        for adapter in adapters {
116→            adapter.stop().await;
117→            debug!("Stopped adapter: {}", adapter.name());
118→        }
119→    }
120→
121→    /// Register an adapter without starting it
122→    pub async fn register(&self, prefix: &str, enabled: bool) {
123→        let mut adapters = self.adapters.write().await;
124→        adapters.insert(
125→            prefix.to_string(),
126→            RegisteredAdapter {
127→                prefix: prefix.to_string(),
128→                enabled,
129→                handle: None,
130→                cancel: self.shutdown.child_token(),
131→            },
132→        );
133→        debug!("Registered adapter: {} (enabled: {})", prefix, enabled);
134→    }
135→
136→    /// Start an adapter with the given spawn function
137→    /// The spawn function receives (bus, cancel_token) and should spawn the adapter task
138→    pub async fn start_adapter<F, Fut>(&self, prefix: &str, spawn_fn: F) -> Result<()>
139→    where
140→        F: FnOnce(SharedBus, CancellationToken) -> Fut,
141→        Fut: std::future::Future<Output = ()> + Send + 'static,
142→    {
143→        let mut adapters = self.adapters.write().await;
144→
145→        let adapter = adapters
146→            .get_mut(prefix)
147→            .ok_or_else(|| anyhow::anyhow!("Adapter {} not registered", prefix))?;
148→
149→        if !adapter.enabled {
150→            debug!("Adapter {} is disabled, not starting", prefix);
151→            return Ok(());
152→        }
153→
154→        if adapter.handle.is_some() {
155→            debug!("Adapter {} already running", prefix);
156→            return Ok(());
157→        }
158→
159→        let bus = self.bus.clone();
160→        let cancel = adapter.cancel.clone();
161→
162→        let handle = tokio::spawn(spawn_fn(bus, cancel));
163→        adapter.handle = Some(handle);
164→
165→        info!("Started adapter: {}", prefix);
166→        Ok(())
167→    }
168→
169→    /// Enable/disable an adapter
170→    pub async fn set_enabled(&self, prefix: &str, enabled: bool) {
171→        let mut adapters = self.adapters.write().await;
172→        if let Some(adapter) = adapters.get_mut(prefix) {
173→            adapter.enabled = enabled;
174→            debug!("Adapter {} enabled: {}", prefix, enabled);
175→        }
176→    }
177→
178→    /// Check if an adapter is enabled
179→    pub async fn is_enabled(&self, prefix: &str) -> bool {
180→        let adapters = self.adapters.read().await;
181→        adapters.get(prefix).map(|a| a.enabled).unwrap_or(false)
182→    }
183→
184→    /// Check if an adapter is running
185→    pub async fn is_running(&self, prefix: &str) -> bool {
186→        let adapters = self.adapters.read().await;
187→        adapters
188→            .get(prefix)
189→            .map(|a| a.handle.is_some())
190→            .unwrap_or(false)
191→    }
192→
193→    /// Stop a single adapter
194→    pub async fn stop_adapter(&self, prefix: &str) -> Result<()> {
195→        // Extract handle while holding lock, reset token immediately to avoid race
196→        // with concurrent start_adapter cloning a cancelled token
197→        let handle = {
198→            let mut adapters = self.adapters.write().await;
199→
200→            let adapter = adapters
201→                .get_mut(prefix)
202→                .ok_or_else(|| anyhow::anyhow!("Adapter {} not registered", prefix))?;
203→
204→            if adapter.handle.is_none() {
205→                debug!("Adapter {} not running", prefix);
206→                return Ok(());
207→            }
208→
209→            info!("Stopping adapter: {}", prefix);
210→
211→            // Cancel the adapter's token
212→            adapter.cancel.cancel();
213→
214→            // Reset token immediately so concurrent start_adapter gets fresh token
215→            adapter.cancel = self.shutdown.child_token();
216→
217→            // Take the handle - lock released after this block
218→            adapter.handle.take()
219→        };
220→
221→        // Wait for the task to complete with timeout (lock not held)
222→        if let Some(handle) = handle {
223→            match tokio::time::timeout(self.shutdown_timeout, handle).await {
224→                Ok(Ok(())) => {
225→                    info!("Adapter {} stopped cleanly", prefix);
226→                }
227→                Ok(Err(e)) => {
228→                    error!("Adapter {} task panicked: {}", prefix, e);
229→                }
230→                Err(_) => {
231→                    warn!("Adapter {} did not stop within timeout, abandoning", prefix);
232→                }
233→            }
234→        }
235→
236→        Ok(())
237→    }
238→
239→    /// Graceful shutdown of all adapters
240→    /// 1. Publish ShuttingDown event
241→    /// 2. Wait for AdapterStopped ACKs
242→    /// 3. Cancel any remaining tasks
243→    pub async fn shutdown(&self) {
244→        info!("Coordinator initiating shutdown");
245→
246→        // Get list of running adapters
247→        let running: Vec<String> = {
248→            let adapters = self.adapters.read().await;
249→            adapters
250→                .iter()
251→                .filter(|(_, a)| a.handle.is_some())
252→                .map(|(prefix, _)| prefix.clone())
253→                .collect()
254→        };
255→
256→        if running.is_empty() {
257→            info!("No adapters running, shutdown complete");
258→            return;
259→        }
260→
261→        info!("Shutting down {} adapter(s): {:?}", running.len(), running);
262→
263→        // Publish ShuttingDown event
264→        self.bus.publish(BusEvent::ShuttingDown {
265→            reason: Some("Coordinator shutdown".to_string()),
266→        });
267→
268→        // Wait for AdapterStopped ACKs with timeout
269→        let acks_received = self.wait_for_acks(&running).await;
270→
271→        if acks_received < running.len() {
272→            warn!(
273→                "Only received {}/{} shutdown ACKs, forcing remaining",
274→                acks_received,
275→                running.len()
276→            );
277→        }
278→
279→        // Cancel global token (catches any stragglers)
280→        self.shutdown.cancel();
281→
282→        // Collect all task handles (release lock before awaiting)
283→        let handles: Vec<(String, tokio::task::JoinHandle<()>)> = {
284→            let mut adapters = self.adapters.write().await;
285→            adapters
286→                .iter_mut()
287→                .filter_map(|(prefix, adapter)| adapter.handle.take().map(|h| (prefix.clone(), h)))
288→                .collect()
289→        };
290→
291→        // Wait for all task handles (lock not held)
292→        for (prefix, handle) in handles {
293→            match tokio::time::timeout(Duration::from_secs(1), handle).await {
294→                Ok(Ok(())) => debug!("Adapter {} task joined", prefix),
295→                Ok(Err(e)) => warn!("Adapter {} task panicked: {}", prefix, e),
296→                Err(_) => warn!("Adapter {} task did not join, abandoning", prefix),
297→            }
298→        }
299→
300→        info!("Coordinator shutdown complete");
301→    }
302→
303→    /// Wait for AdapterStopped events from running adapters
304→    async fn wait_for_acks(&self, expected: &[String]) -> usize {
305→        let mut rx = self.bus.subscribe();
306→        let mut received: Vec<String> = Vec::new();
307→
308→        let deadline = tokio::time::Instant::now() + self.shutdown_timeout;
309→
310→        while received.len() < expected.len() {
311→            let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
312→            if remaining.is_zero() {
313→                break;
314→            }
315→
316→            match tokio::time::timeout(remaining, rx.recv()).await {
317→                Ok(Ok(BusEvent::AdapterStopped { adapter })) => {
318→                    if expected.contains(&adapter) && !received.contains(&adapter) {
319→                        debug!("Received ACK from adapter: {}", adapter);
320→                        received.push(adapter);
321→                    }
322→                }
323→                Ok(Ok(_)) => {
324→                    // Other event, continue waiting
325→                }
326→                Ok(Err(_)) => {
327→                    // Channel closed
328→                    break;
329→                }
330→                Err(_) => {
331→                    // Timeout
332→                    break;
333→                }
334→            }
335→        }
336→
337→        received.len()
338→    }
339→
340→    /// Get list of registered adapter prefixes
341→    pub async fn registered_adapters(&self) -> Vec<String> {
342→        self.adapters.read().await.keys().cloned().collect()
343→    }
344→
345→    /// Get adapter status for debugging/monitoring
346→    pub async fn adapter_status(&self) -> HashMap<String, AdapterStatus> {
347→        let adapters = self.adapters.read().await;
348→        adapters
349→            .iter()
350→            .map(|(prefix, adapter)| {
351→                (
352→                    prefix.clone(),
353→                    AdapterStatus {
354→                        prefix: prefix.clone(),
355→                        enabled: adapter.enabled,
356→                        running: adapter.handle.is_some(),
357→                    },
358→                )
359→            })
360→            .collect()
361→    }
362→}
363→
364→/// Status information for an adapter
365→#[derive(Debug, Clone)]
366→pub struct AdapterStatus {
367→    pub prefix: String,
368→    pub enabled: bool,
369→    pub running: bool,
370→}
