372→#[cfg(test)]
373→mod tests {
374→    use super::*;
375→    use crate::bus::create_bus;
376→    use std::sync::atomic::{AtomicBool, Ordering};
377→    use std::sync::Arc;
378→
379→    #[tokio::test]
380→    async fn test_register_and_check_enabled() {
381→        let bus = create_bus();
382→        let coord = AdapterCoordinator::new(bus);
383→
384→        coord.register("test", true).await;
385→        assert!(coord.is_enabled("test").await);
386→
