  1→//! ZoneAggregator - Single source of truth for zone state
  2→
  3→use std::collections::HashMap;
  4→use std::sync::Arc;
  5→use tokio::sync::RwLock;
  6→use tracing::{debug, info};
  7→
  8→use crate::bus::{BusEvent, NowPlaying, SharedBus, Zone};
  9→
 10→/// ZoneAggregator maintains unified zone state from all adapters.
 11→/// - Subscribes to bus events
 12→/// - Maintains HashMap of zones by zone_id
 13→/// - Flushes zones when adapter stops
 14→/// - Provides query interface for API layer
 15→pub struct ZoneAggregator {
 16→    zones: Arc<RwLock<HashMap<String, Zone>>>,
 17→    bus: SharedBus,
 18→}
 19→
 20→impl ZoneAggregator {
 21→    pub fn new(bus: SharedBus) -> Self {
 22→        Self {
 23→            zones: Arc::new(RwLock::new(HashMap::new())),
 24→            bus,
 25→        }
 26→    }
 27→
 28→    /// Start the aggregator's event processing loop
 29→    /// Should be spawned as a task
 30→    pub async fn run(&self) {
 31→        let mut rx = self.bus.subscribe();
 32→
 33→        info!("ZoneAggregator started");
 34→
 35→        while let Ok(event) = rx.recv().await {
 36→            match event {
 37→                BusEvent::ZoneDiscovered { zone } => {
 38→                    debug!("Zone discovered: {}", zone.zone_id);
 39→                    self.zones.write().await.insert(zone.zone_id.clone(), zone);
 40→                }
 41→
 42→                BusEvent::ZoneUpdated {
 43→                    zone_id,
 44→                    display_name,
 45→                    state,
 46→                } => {
 47→                    debug!("Zone updated: {}", zone_id);
 48→                    if let Some(zone) = self.zones.write().await.get_mut(zone_id.as_str()) {
 49→                        zone.zone_name = display_name;
 50→                        zone.state = state.as_str().into();
 51→                    }
 52→                }
 53→
 54→                BusEvent::ZoneRemoved { zone_id } => {
 55→                    debug!("Zone removed: {}", zone_id);
 56→                    self.zones.write().await.remove(zone_id.as_str());
 57→                }
 58→
 59→                BusEvent::NowPlayingChanged {
 60→                    zone_id,
 61→                    title,
 62→                    artist,
 63→                    album,
 64→                    image_key,
 65→                } => {
 66→                    debug!("Now playing changed: {}", zone_id);
 67→                    if let Some(zone) = self.zones.write().await.get_mut(zone_id.as_str()) {
 68→                        // Preserve seek_position and duration from existing now_playing
 69→                        let (seek_position, duration) = zone
 70→                            .now_playing
 71→                            .as_ref()
 72→                            .map(|np| (np.seek_position, np.duration))
 73→                            .unwrap_or((None, None));
 74→
 75→                        zone.now_playing = Some(NowPlaying {
 76→                            title: title.unwrap_or_default(),
 77→                            artist: artist.unwrap_or_default(),
 78→                            album: album.unwrap_or_default(),
 79→                            image_key,
 80→                            seek_position,
 81→                            duration,
 82→                            metadata: None,
 83→                        });
 84→                    }
 85→                }
 86→
 87→                BusEvent::VolumeChanged {
 88→                    output_id,
 89→                    value,
 90→                    is_muted,
 91→                } => {
 92→                    debug!(
 93→                        "Volume changed: {} = {} (muted: {})",
 94→                        output_id, value, is_muted
 95→                    );
 96→                    // Find zone containing this output and update volume_control
 97→                    // All adapters must use prefixed output_ids (e.g., "lms:xx:xx:xx", "roon:output-id")
 98→                    // The lint test `bus_events_use_prefixed_output_ids` enforces this.
 99→                    let mut zones = self.zones.write().await;
100→                    for zone in zones.values_mut() {
101→                        let matches = zone
102→                            .volume_control
103→                            .as_ref()
104→                            .and_then(|vc| vc.output_id.as_ref())
105→                            .map(|oid| oid == &output_id)
106→                            .unwrap_or(false);
107→
108→                        if matches {
109→                            if let Some(ref mut vc) = zone.volume_control {
110→                                vc.value = value;
111→                                vc.is_muted = is_muted;
112→                            }
113→                            break;
114→                        }
115→                    }
116→                }
117→
118→                BusEvent::SeekPositionChanged { zone_id, position } => {
119→                    debug!("Seek position changed: {} = {}", zone_id, position);
120→                    if let Some(zone) = self.zones.write().await.get_mut(zone_id.as_str()) {
121→                        if let Some(ref mut np) = zone.now_playing {
122→                            np.seek_position = Some(position as f64);
123→                        }
124→                    }
125→                }
126→
127→                BusEvent::AdapterStopping { adapter, .. } => {
128→                    info!("Flushing zones for adapter: {}", adapter);
129→                    let prefix = format!("{}:", adapter);
130→
131→                    // Remove all zones with this prefix
132→                    let mut zones = self.zones.write().await;
133→
134→                    let zone_ids: Vec<String> = zones
135→                        .keys()
136→                        .filter(|k| k.starts_with(&prefix))
137→                        .cloned()
138→                        .collect();
139→
140→                    for zone_id in &zone_ids {
141→                        zones.remove(zone_id);
142→                    }
143→
144→                    // Publish flush acknowledgment
145→                    self.bus.publish(BusEvent::ZonesFlushed {
146→                        adapter: adapter.clone(),
147→                        zone_ids,
148→                    });
149→                }
150→
151→                BusEvent::ShuttingDown { .. } => {
152→                    info!("ZoneAggregator shutting down");
153→                    break;
154→                }
155→
156→                _ => {
157→                    // Ignore other events
158→                }
159→            }
160→        }
161→
162→        info!("ZoneAggregator stopped");
163→    }
164→
165→    /// Get all zones
166→    pub async fn get_zones(&self) -> Vec<Zone> {
167→        self.zones.read().await.values().cloned().collect()
168→    }
169→
170→    /// Get zones for a specific adapter
171→    pub async fn get_zones_by_adapter(&self, adapter: &str) -> Vec<Zone> {
172→        let prefix = format!("{}:", adapter);
173→        self.zones
174→            .read()
175→            .await
176→            .values()
177→            .filter(|z| z.zone_id.starts_with(&prefix))
178→            .cloned()
179→            .collect()
180→    }
181→
182→    /// Get a specific zone
183→    pub async fn get_zone(&self, zone_id: &str) -> Option<Zone> {
184→        self.zones.read().await.get(zone_id).cloned()
185→    }
186→
187→    /// Get now playing for a zone
188→    pub async fn get_now_playing(&self, zone_id: &str) -> Option<NowPlaying> {
189→        self.zones
190→            .read()
191→            .await
192→            .get(zone_id)
193→            .and_then(|z| z.now_playing.clone())
194→    }
195→
196→    /// Get zone count
197→    pub async fn zone_count(&self) -> usize {
198→        self.zones.read().await.len()
199→    }
200→}
