  1→//! AdapterHandle - Wraps AdapterLogic with consistent lifecycle management
  2→//!
  3→//! Provides automatic retry with exponential backoff when adapters encounter errors.
  4→//! All retry logic is centralized here - adapters should NOT implement their own retry loops.
  5→
  6→use anyhow::Result;
  7→use std::sync::Arc;
  8→use std::time::{Duration, Instant};
  9→use tokio_util::sync::CancellationToken;
 10→use tracing::{error, info, warn};
 11→
 12→use crate::adapters::traits::{AdapterContext, AdapterLogic};
 13→use crate::bus::{BusEvent, SharedBus};
 14→
 15→/// Retry configuration for adapter startup/run
 16→#[derive(Debug, Clone)]
 17→pub struct RetryConfig {
 18→    /// Initial delay between retry attempts
 19→    pub initial_delay: Duration,
 20→    /// Maximum delay (backoff caps at this value)
 21→    pub max_delay: Duration,
 22→    /// Minimum run time before resetting backoff on failure
 23→    /// If the adapter runs for at least this long before failing,
 24→    /// the backoff delay resets to initial_delay
 25→    pub stable_run_threshold: Duration,
 26→}
 27→
 28→impl Default for RetryConfig {
 29→    fn default() -> Self {
 30→        Self {
 31→            initial_delay: Duration::from_secs(5),
 32→            max_delay: Duration::from_secs(60),
 33→            stable_run_threshold: Duration::from_secs(30),
 34→        }
 35→    }
 36→}
 37→
 38→impl RetryConfig {
 39→    /// Create a new RetryConfig with custom delays
 40→    pub fn new(initial_delay: Duration, max_delay: Duration) -> Self {
 41→        Self {
 42→            initial_delay,
 43→            max_delay,
 44→            stable_run_threshold: Duration::from_secs(30),
 45→        }
 46→    }
 47→}
 48→
 49→/// AdapterHandle wraps an AdapterLogic implementation and provides:
 50→/// - Consistent shutdown handling (can't forget it)
 51→/// - Automatic ACK on stop via AdapterStopped event
 52→/// - ShuttingDown event watching
 53→/// - Automatic retry with exponential backoff
 54→pub struct AdapterHandle<T: AdapterLogic> {
 55→    logic: Arc<T>,
 56→    bus: SharedBus,
 57→    shutdown: CancellationToken,
 58→}
 59→
 60→impl<T: AdapterLogic> AdapterHandle<T> {
 61→    pub fn new(logic: T, bus: SharedBus, shutdown: CancellationToken) -> Self {
 62→        Self {
 63→            logic: Arc::new(logic),
 64→            bus,
 65→            shutdown,
 66→        }
 67→    }
 68→
 69→    /// Get the adapter's prefix
 70→    pub fn prefix(&self) -> &'static str {
 71→        self.logic.prefix()
 72→    }
 73→
 74→    /// Get access to the underlying logic (for command handling)
 75→    pub fn logic(&self) -> &Arc<T> {
 76→        &self.logic
 77→    }
 78→
 79→    /// Run the adapter with lifecycle management (single attempt, no retry)
 80→    /// - Calls init() if implemented
 81→    /// - Runs the adapter's main loop
 82→    /// - Watches for ShuttingDown events on the bus
 83→    /// - Publishes AdapterStopped on exit
 84→    ///
 85→    /// For automatic retry on error, use `run_with_retry()` instead.
 86→    pub async fn run(self) -> Result<()> {
 87→        let prefix = self.logic.prefix();
 88→        info!("Starting adapter: {}", prefix);
 89→
 90→        // Run once without retry
 91→        let result = self.run_once().await;
 92→
 93→        // Automatic ACK - publish AdapterStopped
 94→        self.bus.publish(BusEvent::AdapterStopped {
 95→            adapter: prefix.to_string(),
 96→        });
 97→
 98→        info!("Adapter {} stopped", prefix);
 99→        result
100→    }
101→
102→    /// Run the adapter with automatic retry on error
103→    ///
104→    /// When `run()` returns `Err`, waits with exponential backoff and retries.
105→    /// When `run()` returns `Ok`, exits cleanly.
106→    ///
107→    /// Backoff is reset to initial delay if the adapter ran stably for at least
108→    /// `config.stable_run_threshold` (default 30s) before failing.
109→    ///
110→    /// This is the preferred method for production use - it handles transient
111→    /// failures like service restarts automatically.
112→    pub async fn run_with_retry(self, config: RetryConfig) -> Result<()> {
113→        let prefix = self.logic.prefix();
114→        let mut delay = config.initial_delay;
115→
116→        loop {
117→            // Check for shutdown before attempting
118→            if self.shutdown.is_cancelled() {
119→                info!("{}: shutdown before attempt", prefix);
120→                break;
121→            }
122→
123→            info!("{}: starting (retry delay: {:?})", prefix, delay);
124→
125→            let start = Instant::now();
126→            match self.run_once().await {
127→                Ok(()) => {
128→                    info!("{}: clean exit", prefix);
129→                    break;
130→                }
131→                Err(e) => {
132→                    let run_duration = start.elapsed();
133→
134→                    // Reset backoff if we had a stable run before failing
135→                    if run_duration >= config.stable_run_threshold {
136→                        info!(
137→                            "{}: ran for {:?} before failure, resetting backoff",
138→                            prefix, run_duration
139→                        );
140→                        delay = config.initial_delay;
141→                    }
142→
143→                    warn!("{}: error ({}), retrying in {:?}", prefix, e, delay);
144→
145→                    // Wait with shutdown check
146→                    tokio::select! {
147→                        _ = self.shutdown.cancelled() => {
148→                            info!("{}: shutdown during backoff", prefix);
149→                            break;
150→                        }
151→                        _ = tokio::time::sleep(delay) => {
152→                            // Exponential backoff capped at max_delay
153→                            delay = (delay * 2).min(config.max_delay);
154→                        }
155→                    }
156→                }
157→            }
158→        }
159→
160→        // Automatic ACK - publish AdapterStopped
161→        self.bus.publish(BusEvent::AdapterStopped {
162→            adapter: prefix.to_string(),
163→        });
164→
165→        info!("{}: stopped", prefix);
166→        Ok(())
167→    }
168→
169→    /// Run the adapter once (internal helper)
170→    ///
171→    /// Returns:
172→    /// - `Ok(())` on clean shutdown (adapter should not restart)
173→    /// - `Err(...)` on error (adapter should restart)
174→    async fn run_once(&self) -> Result<()> {
175→        let prefix = self.logic.prefix();
176→
177→        // Initialize
178→        if let Err(e) = self.logic.init().await {
179→            error!("{}: init failed: {}", prefix, e);
180→            return Err(e);
181→        }
182→
183→        // Subscribe to bus for shutdown signal
184→        let mut rx = self.bus.subscribe();
185→
186→        // Create context for the adapter
187→        let ctx = AdapterContext {
188→            bus: self.bus.clone(),
189→            shutdown: self.shutdown.clone(),
190→        };
191→
192→        // Run with lifecycle management
193→        let result = tokio::select! {
194→            // Run adapter-specific logic
195→            result = self.logic.run(ctx) => {
196→                match &result {
197→                    Ok(()) => info!("{}: completed normally", prefix),
198→                    Err(e) => error!("{}: error: {}", prefix, e),
199→                }
200→                result
201→            }
202→
203→            // Watch for shutdown signal on bus
204→            _ = async {
205→                while let Ok(event) = rx.recv().await {
206→                    if matches!(event, BusEvent::ShuttingDown { .. }) {
207→                        info!("{}: received ShuttingDown event", prefix);
208→                        break;
209→                    }
210→                }
211→            } => {
212→                info!("{}: stopping due to ShuttingDown event", prefix);
213→                Ok(())
214→            }
215→
216→            // Direct cancellation (backup mechanism)
217→            _ = self.shutdown.cancelled() => {
218→                info!("{}: cancelled via token", prefix);
219→                Ok(())
220→            }
221→        };
222→
223→        result
224→    }
225→}
