380→        let handle = AdapterHandle::new(adapter, bus, shutdown);
381→        let config = RetryConfig::default();
382→
383→        let result = handle.run_with_retry(config).await;
384→        assert!(result.is_ok());
385→
386→        // Should not have attempted at all
387→        assert_eq!(attempt_tracker.load(Ordering::SeqCst), 0);
388→    }
