413→    /// Mock adapter that runs for configurable durations then fails/succeeds
414→    struct MockTimedAdapter {
415→        /// Durations to run before failing, then succeeds on last call
416→        run_durations: Arc<Mutex<Vec<Duration>>>,
417→        call_count: Arc<AtomicUsize>,
418→        /// Record the delay used before each retry (for verification)
419→        retry_delays: Arc<Mutex<Vec<Instant>>>,
420→    }
421→
422→    impl MockTimedAdapter {
423→        fn new(durations: Vec<Duration>) -> Self {
424→            Self {
425→                run_durations: Arc::new(Mutex::new(durations)),
426→                call_count: Arc::new(AtomicUsize::new(0)),
427→                retry_delays: Arc::new(Mutex::new(Vec::new())),
428→            }
429→        }
430→    }
431→
432→    impl Clone for MockTimedAdapter {
433→        fn clone(&self) -> Self {
434→            Self {
435→                run_durations: self.run_durations.clone(),
436→                call_count: self.call_count.clone(),
437→                retry_delays: self.retry_delays.clone(),
438→            }
439→        }
440→    }
441→
442→    #[async_trait]
443→    impl AdapterLogic for MockTimedAdapter {
444→        fn prefix(&self) -> &'static str {
445→            "mock-timed"
446→        }
447→
448→        async fn run(&self, _ctx: AdapterContext) -> Result<()> {
449→            let count = self.call_count.fetch_add(1, Ordering::SeqCst);
450→
451→            // Record when this attempt started
452→            {
453→                let mut delays = self.retry_delays.lock().unwrap();
454→                delays.push(Instant::now());
455→            }
456→
457→            // Get duration before await (drop lock before sleeping)
458→            let duration = {
459→                let durations = self.run_durations.lock().unwrap();
460→                if count < durations.len() {
461→                    Some(durations[count])
462→                } else {
463→                    None
464→                }
465→            };
466→
467→            if let Some(dur) = duration {
468→                // Sleep for specified duration then fail
469→                tokio::time::sleep(dur).await;
470→                Err(anyhow::anyhow!("Simulated failure after {:?}", dur))
471→            } else {
472→                // No more durations - succeed
473→                Ok(())
474→            }
475→        }
476→
477→        async fn handle_command(
478→            &self,
479→            _zone_id: &str,
480→            _command: AdapterCommand,
481→        ) -> Result<AdapterCommandResponse> {
482→            Ok(AdapterCommandResponse {
483→                success: true,
484→                error: None,
485→            })
486→        }
487→    }
488→
489→    #[tokio::test]
490→    async fn test_backoff_reset_after_stable_run() {
491→        // Test that backoff resets after a stable run
492→        //
493→        // Scenario:
494→        // 1. First run: fails immediately (short run)
495→        // 2. Second run: runs for stable_threshold, then fails
496→        // 3. Third run: succeeds
497→        //
498→        // Expected behavior:
499→        // - After first (short) failure: delay doubles (10ms -> 20ms)
500→        // - After second (stable) failure: delay resets to initial (10ms)
501→
502→        let bus = test_bus();
503→        let shutdown = CancellationToken::new();
504→
505→        // Run durations: 0ms (immediate fail), 60ms (stable), then succeed
506→        let adapter = MockTimedAdapter::new(vec![
507→            Duration::from_millis(0),  // First: immediate failure
508→            Duration::from_millis(60), // Second: stable run then failure
509→        ]);
510→        let retry_delays = adapter.retry_delays.clone();
511→
512→        let handle = AdapterHandle::new(adapter, bus, shutdown);
513→        let config = RetryConfig {
514→            initial_delay: Duration::from_millis(10),
515→            max_delay: Duration::from_millis(100),
516→            stable_run_threshold: Duration::from_millis(50), // 50ms = stable
517→        };
518→
519→        let start = Instant::now();
520→        let result = handle.run_with_retry(config).await;
521→        assert!(result.is_ok());
522→
523→        // Check timing of retry attempts
524→        let delays = retry_delays.lock().unwrap();
525→        assert_eq!(delays.len(), 3, "Should have 3 attempts");
526→
527→        // Gap between attempt 1 and 2: should be ~10ms (initial delay, short run)
528→        let gap1 = delays[1].duration_since(delays[0]);
529→        // Gap between attempt 2 and 3: should be ~10ms (reset after stable run)
530→        // NOT 20ms (which would be doubled delay)
531→        let gap2 = delays[2].duration_since(delays[1]);
532→
533→        // Allow some tolerance for timing
534→        // First gap: 0ms run + 10ms wait = ~10ms
535→        assert!(
536→            gap1 >= Duration::from_millis(8) && gap1 <= Duration::from_millis(25),
537→            "First gap should be ~10ms, was {:?}",
538→            gap1
539→        );
540→
541→        // Second gap: 60ms run + 10ms wait (reset) = ~70ms
542→        // If backoff wasn't reset, it would be 60ms run + 20ms wait = ~80ms
543→        assert!(
544→            gap2 >= Duration::from_millis(65) && gap2 <= Duration::from_millis(85),
545→            "Second gap should be ~70ms (with reset), was {:?}",
546→            gap2
547→        );
548→
549→        // Total time sanity check
550→        let total = start.elapsed();
551→        assert!(
552→            total < Duration::from_millis(150),
553→            "Total time too long: {:?}",
554→            total
555→        );
556→    }
557→}
