 133→struct OpenHomeState {
 134→    devices: HashMap<String, OpenHomeDevice>,
 135→    running: bool,
 136→}
 137→
 138→/// OpenHome adapter for discovering and controlling OpenHome devices
 139→#[derive(Clone)]
 140→pub struct OpenHomeAdapter {
 141→    state: Arc<RwLock<OpenHomeState>>,
 142→    bus: SharedBus,
 143→    http: Client,
 144→    /// Wrapped in RwLock to allow creating fresh token on restart
 145→    shutdown: Arc<RwLock<CancellationToken>>,
 146→}
 147→
 148→impl OpenHomeAdapter {
 149→    /// Create new OpenHome adapter
 150→    pub fn new(bus: SharedBus) -> Self {
 151→        Self {
 152→            state: Arc::new(RwLock::new(OpenHomeState {
 153→                devices: HashMap::new(),
 154→                running: false,
 155→            })),
 156→            bus,
 157→            http: Client::builder()
 158→                .timeout(SOAP_TIMEOUT)
 159→                .build()
 160→                .unwrap_or_default(),
 161→            shutdown: Arc::new(RwLock::new(CancellationToken::new())),
 162→        }
 163→    }
 164→
 165→    /// Start SSDP discovery (internal - use Startable trait)
 166→    async fn start_internal(&self) -> anyhow::Result<()> {
 167→        // Use write lock to atomically check and set running flag
 168→        // This prevents race conditions where multiple starts could pass the check
 169→        {
 170→            let mut state = self.state.write().await;
 171→            if state.running {
 172→                return Ok(());
 173→            }
 174→            state.running = true;
 175→        }
 176→
 177→        // Create fresh cancellation token for this run (previous token may be cancelled)
 178→        let shutdown = {
 179→            let mut token = self.shutdown.write().await;
 180→            *token = CancellationToken::new();
 181→            token.clone()
 182→        };
 183→
 184→        // Create AdapterHandle and spawn run_with_retry
 185→        let handle = AdapterHandle::new(self.clone(), self.bus.clone(), shutdown);
 186→
 187→        tokio::spawn(async move {
 188→            let _ = handle.run_with_retry(RetryConfig::default()).await;
 189→        });
 190→
 191→        tracing::info!("OpenHome adapter started");
 192→        Ok(())
 193→    }
 194→
 195→    async fn discovery_loop(
 196→        state: Arc<RwLock<OpenHomeState>>,
 197→        bus: SharedBus,
 198→        http: Client,
 199→        shutdown: CancellationToken,
 200→    ) {
 201→        let mut search_interval = interval(SSDP_SEARCH_INTERVAL);
 202→
 203→        loop {
 204→            tokio::select! {
 205→                _ = shutdown.cancelled() => {
 206→                    tracing::info!("OpenHome discovery loop shutting down");
 207→                    break;
 208→                }
 209→                _ = search_interval.tick() => {
 210→                    // Perform SSDP search
 211→                    if let Err(e) = Self::perform_search(&state, &bus, &http).await {
 212→                        tracing::warn!("SSDP search failed: {}", e);
 213→                    }
 214→
 215→                    // Cleanup stale devices
 216→                    Self::cleanup_stale(&state, &bus).await;
 217→                }
 218→            }
 219→        }
 220→
 221→        tracing::info!("OpenHome discovery loop stopped");
 222→    }
 223→
 224→    async fn perform_search(
 225→        state: &Arc<RwLock<OpenHomeState>>,
 226→        bus: &SharedBus,
 227→        http: &Client,
 228→    ) -> anyhow::Result<()> {
 229→        // Search for all known OpenHome URNs - devices may advertise different services
 230→        for urn_str in OPENHOME_URNS {
 231→            let urn: URN = match urn_str.parse() {
 232→                Ok(u) => u,
 233→                Err(e) => {
 234→                    tracing::warn!("Failed to parse URN {}: {}", urn_str, e);
 235→                    continue;
 236→                }
 237→            };
 238→            let search_target = SearchTarget::URN(urn);
 239→
 240→            match ssdp_client::search(&search_target, Duration::from_secs(2), 2, None).await {
 241→                Ok(responses) => {
 242→                    futures::pin_mut!(responses);
 243→
 244→                    while let Some(response) = responses.next().await {
 245→                        let response = match response {
 246→                            Ok(r) => r,
 247→                            Err(e) => {
 248→                                tracing::debug!("SSDP response error: {}", e);
 249→                                continue;
 250→                            }
 251→                        };
 252→
 253→                        let location = response.location().to_string();
 254→                        let usn = response.usn();
 255→
 256→                        // Log what we're finding
 257→                        tracing::debug!("OpenHome SSDP response: usn={} loc={}", usn, location);
 258→
 259→                        // Extract UUID from USN
 260→                        let uuid = match usn.split("::").next() {
 261→                            Some(s) if s.starts_with("uuid:") => {
 262→                                s.trim_start_matches("uuid:").to_string()
 263→                            }
 264→                            _ => continue,
 265→                        };
 266→
 267→                        // Update existing or add new
 268→                        let mut s = state.write().await;
 269→                        if let Some(device) = s.devices.get_mut(&uuid) {
 270→                            device.last_seen = std::time::Instant::now();
 271→                            continue;
 272→                        }
 273→
 274→                        tracing::info!(
 275→                            "Discovered OpenHome device: {} at {} (via {})",
 276→                            uuid,
 277→                            location,
 278→                            urn_str
 279→                        );
 280→
 281→                        // New device
 282→                        let device = OpenHomeDevice {
 283→                            uuid: uuid.clone(),
 284→                            name: format!("OpenHome {}", &uuid[..8.min(uuid.len())]),
 285→                            manufacturer: None,
 286→                            model: None,
 287→                            location: location.clone(),
 288→                            state: "stopped".to_string(),
 289→                            volume: None,
 290→                            muted: false,
 291→                            volume_max: None,
 292→                            volume_steps: None,
 293→                            track_info: None,
 294→                            last_seen: std::time::Instant::now(),
 295→                            last_track_uri: None,
 296→                        };
 297→
 298→                        s.devices.insert(uuid.clone(), device);
 299→                        drop(s);
 300→
 301→                        // Fetch device description
 302→                        let state_clone = state.clone();
 303→                        let http_clone = http.clone();
 304→                        let bus_clone = bus.clone();
 305→                        let uuid_clone = uuid.clone();
 306→
 307→                        tokio::spawn(async move {
 308→                            if let Err(e) = Self::fetch_device_info(
 309→                                &state_clone,
 310→                                &http_clone,
 311→                                &uuid_clone,
 312→                                &location,
 313→                            )
 314→                            .await
 315→                            {
 316→                                tracing::warn!(
 317→                                    "Failed to fetch device info for {}: {}",
 318→                                    uuid_clone,
 319→                                    e
 320→                                );
 321→                            }
 322→                            // Emit ZoneDiscovered with full zone info
 323→                            let s = state_clone.read().await;
 324→                            if let Some(device) = s.devices.get(&uuid_clone) {
 325→                                let zone = openhome_device_to_zone(device);
 326→                                bus_clone.publish(BusEvent::ZoneDiscovered { zone });
 327→                            }
 328→                        });
 329→                    }
 330→                }
 331→                Err(e) => {
 332→                    tracing::debug!("SSDP search for {} failed: {}", urn_str, e);
 333→                }
 334→            }
 335→        }
 336→
 337→        Ok(())
 338→    }
 339→
 340→    async fn fetch_device_info(
 341→        state: &Arc<RwLock<OpenHomeState>>,
 342→        http: &Client,
 343→        uuid: &str,
 344→        location: &str,
 345→    ) -> anyhow::Result<()> {
 346→        let response = http.get(location).send().await?;
 347→        let xml = response.text().await?;
 348→
 349→        // Parse device description
 350→        #[derive(Deserialize)]
 351→        struct Root {
 352→            device: DeviceDesc,
 353→        }
 354→
 355→        #[derive(Deserialize)]
 356→        struct DeviceDesc {
 357→            #[serde(rename = "friendlyName")]
 358→            friendly_name: Option<String>,
 359→            manufacturer: Option<String>,
 360→            #[serde(rename = "modelName")]
 361→            model_name: Option<String>,
 362→        }
 363→
 364→        let root: Root = xml_from_str(&xml)?;
 365→
 366→        let mut s = state.write().await;
 367→        if let Some(device) = s.devices.get_mut(uuid) {
 368→            device.name = root
 369→                .device
 370→                .friendly_name
 371→                .unwrap_or_else(|| format!("OpenHome {}", &uuid[..8.min(uuid.len())]));
 372→            device.manufacturer = root.device.manufacturer;
 373→            device.model = root.device.model_name;
 374→
 375→            tracing::info!(
 376→                "Got OpenHome device info: {} - {} {}",
 377→                device.name,
 378→                device.manufacturer.as_deref().unwrap_or("Unknown"),
 379→                device.model.as_deref().unwrap_or("")
 380→            );
 381→        }
 382→
 383→        Ok(())
 384→    }
 385→
 386→    async fn cleanup_stale(state: &Arc<RwLock<OpenHomeState>>, bus: &SharedBus) {
 387→        let mut s = state.write().await;
 388→        let now = std::time::Instant::now();
 389→
 390→        let stale: Vec<String> = s
 391→            .devices
 392→            .iter()
 393→            .filter(|(_, d)| now.duration_since(d.last_seen) > STALE_THRESHOLD)
 394→            .map(|(uuid, _)| uuid.clone())
 395→            .collect();
 396→
 397→        for uuid in stale {
 398→            tracing::info!("Removing stale OpenHome device: {}", uuid);
 399→            s.devices.remove(&uuid);
 400→            bus.publish(BusEvent::ZoneRemoved {
 401→                zone_id: PrefixedZoneId::openhome(&uuid),
 402→            });
 403→        }
 404→    }
 405→
 406→    async fn poll_loop(
 407→        state: Arc<RwLock<OpenHomeState>>,
 408→        bus: SharedBus,
 409→        http: Client,
 410→        shutdown: CancellationToken,
 411→    ) {
 412→        let mut poll_interval = interval(POLL_INTERVAL);
 413→
 414→        loop {
 415→            tokio::select! {
 416→                _ = shutdown.cancelled() => {
 417→                    tracing::info!("OpenHome poll loop shutting down");
 418→                    break;
 419→                }
 420→                _ = poll_interval.tick() => {
 421→                    // Get list of devices to poll
 422→                    let devices: Vec<(String, String)> = {
 423→                        let s = state.read().await;
 424→                        s.devices
 425→                            .iter()
 426→                            .map(|(uuid, d)| (uuid.clone(), d.location.clone()))
 427→                            .collect()
 428→                    };
 429→
 430→                    for (uuid, location) in devices {
 431→                        if let Err(e) = Self::poll_device(&state, &bus, &http, &uuid, &location).await {
 432→                            tracing::debug!("Failed to poll {}: {}", uuid, e);
 433→                        }
 434→                    }
 435→                }
 436→            }
 437→        }
 438→
 439→        tracing::info!("OpenHome poll loop stopped");
 440→    }
 441→
 442→    async fn poll_device(
 443→        state: &Arc<RwLock<OpenHomeState>>,
 444→        bus: &SharedBus,
 445→        http: &Client,
 446→        uuid: &str,
 447→        location: &str,
 448→    ) -> anyhow::Result<()> {
 449→        let base_url = Self::get_base_url(location)?;
 450→
 451→        // Poll transport state
 452→        let transport_state = Self::soap_call(
 453→            http,
 454→            &format!("{}/Transport", base_url),
 455→            "urn:av-openhome-org:service:Transport:1",
 456→            "TransportState",
 457→            "",
 458→        )
 459→        .await;
 460→
 461→        if let Ok(response) = transport_state {
 462→            if let Some(new_state) = Self::extract_xml_value(&response, "Value") {
 463→                let new_state = new_state.to_lowercase();
 464→                let mut s = state.write().await;
 465→                if let Some(device) = s.devices.get_mut(uuid) {
 466→                    if device.state != new_state {
 467→                        device.state = new_state.clone();
 468→                        bus.publish(BusEvent::ZoneUpdated {
 469→                            zone_id: PrefixedZoneId::openhome(uuid),
 470→                            display_name: device.name.clone(),
 471→                            state: new_state,
 472→                        });
 473→                    }
 474→                }
 475→            }
 476→        }
 477→
 478→        // Poll volume
 479→        let volume = Self::soap_call(
 480→            http,
 481→            &format!("{}/Volume", base_url),
 482→            "urn:av-openhome-org:service:Volume:1",
 483→            "Volume",
 484→            "",
 485→        )
 486→        .await;
 487→
 488→        if let Ok(response) = volume {
 489→            if let Some(vol_str) = Self::extract_xml_value(&response, "Value") {
 490→                if let Ok(vol) = vol_str.parse::<i32>() {
 491→                    let mut s = state.write().await;
 492→                    if let Some(device) = s.devices.get_mut(uuid) {
 493→                        device.volume = Some(vol);
 494→                    }
 495→                }
 496→            }
 497→        }
 498→
 499→        // Poll mute state
 500→        let mute = Self::soap_call(
 501→            http,
 502→            &format!("{}/Volume", base_url),
 503→            "urn:av-openhome-org:service:Volume:1",
 504→            "Mute",
 505→            "",
 506→        )
 507→        .await;
 508→
 509→        if let Ok(response) = mute {
 510→            if let Some(mute_str) = Self::extract_xml_value(&response, "Value") {
 511→                let is_muted = mute_str == "true" || mute_str == "1";
 512→                let mut s = state.write().await;
 513→                if let Some(device) = s.devices.get_mut(uuid) {
 514→                    device.muted = is_muted;
 515→                }
 516→            }
 517→        }
 518→
 519→        // Poll volume characteristics for step calculation
 520→        // See: http://wiki.openhome.org/wiki/Av:Developer:VolumeService
 521→        let characteristics = Self::soap_call(
 522→            http,
 523→            &format!("{}/Volume", base_url),
 524→            "urn:av-openhome-org:service:Volume:1",
 525→            "Characteristics",
 526→            "",
 527→        )
 528→        .await;
 529→
 530→        if let Ok(response) = characteristics {
 531→            let mut s = state.write().await;
 532→            if let Some(device) = s.devices.get_mut(uuid) {
 533→                if let Some(max_str) = Self::extract_xml_value(&response, "VolumeMax") {
 534→                    device.volume_max = max_str.parse().ok();
 535→                }
 536→                if let Some(steps_str) = Self::extract_xml_value(&response, "VolumeSteps") {
 537→                    device.volume_steps = steps_str.parse().ok();
 538→                }
 539→            }
 540→        }
 541→
 542→        // Poll track info
 543→        let track = Self::soap_call(
 544→            http,
 545→            &format!("{}/Info", base_url),
 546→            "urn:av-openhome-org:service:Info:1",
 547→            "Track",
 548→            "",
 549→        )
 550→        .await;
 551→
 552→        if let Ok(response) = track {
 553→            let uri = Self::extract_xml_value(&response, "Uri");
 554→            let metadata = Self::extract_xml_value(&response, "Metadata");
 555→
 556→            let mut s = state.write().await;
 557→            if let Some(device) = s.devices.get_mut(uuid) {
 558→                // Only parse if URI changed
 559→                if uri.as_ref() != device.last_track_uri.as_ref() {
 560→                    device.last_track_uri = uri;
 561→
 562→                    if let Some(meta) = metadata {
 563→                        // Decode HTML entities and parse DIDL-Lite
 564→                        let decoded = html_decode(&meta);
 565→                        if let Some(track_info) = Self::parse_didl_lite(&decoded) {
 566→                            let title = Some(track_info.title.clone());
 567→                            let artist = Some(track_info.artist.clone());
 568→                            let album = Some(track_info.album.clone());
 569→                            let image_key = track_info.album_art_uri.clone();
 570→                            device.track_info = Some(track_info);
 571→                            bus.publish(BusEvent::NowPlayingChanged {
 572→                                zone_id: PrefixedZoneId::openhome(uuid),
 573→                                title,
 574→                                artist,
 575→                                album,
 576→                                image_key,
 577→                            });
 578→                        }
 579→                    }
 580→                }
 581→            }
 582→        }
 583→
 584→        Ok(())
 585→    }
