 587→    fn get_base_url(location: &str) -> anyhow::Result<String> {
 588→        let url = url::Url::parse(location)?;
 589→        let port = url.port().map(|p| format!(":{}", p)).unwrap_or_default();
 590→        Ok(format!(
 591→            "{}://{}{}",
 592→            url.scheme(),
 593→            url.host_str().unwrap_or("localhost"),
 594→            port
 595→        ))
 596→    }
