 598→    async fn soap_call(
 599→        http: &Client,
 600→        url: &str,
 601→        service_type: &str,
 602→        action: &str,
 603→        body_content: &str,
 604→    ) -> anyhow::Result<String> {
 605→        let soap_body = format!(
 606→            r#"<?xml version="1.0" encoding="utf-8"?>
 607→<s:Envelope xmlns:s="http://schemas.xmlsoap.org/soap/envelope/" s:encodingStyle="http://schemas.xmlsoap.org/soap/encoding/">
 608→  <s:Body>
 609→    <u:{action} xmlns:u="{service_type}">{body}</u:{action}>
 610→  </s:Body>
 611→</s:Envelope>"#,
 612→            action = action,
 613→            service_type = service_type,
 614→            body = body_content
 615→        );
 616→
 617→        let response = http
 618→            .post(url)
 619→            .header("Content-Type", "text/xml; charset=utf-8")
 620→            .header("SOAPAction", format!("\"{}#{}\"", service_type, action))
 621→            .body(soap_body)
 622→            .send()
 623→            .await?;
 624→
 625→        Ok(response.text().await?)
 626→    }
 627→
 628→    fn extract_xml_value(xml: &str, tag: &str) -> Option<String> {
 629→        let start_tag = format!("<{}>", tag);
 630→        let end_tag = format!("</{}>", tag);
 631→
 632→        let start = xml.find(&start_tag)? + start_tag.len();
 633→        let end = xml[start..].find(&end_tag)? + start;
 634→
 635→        Some(xml[start..end].to_string())
 636→    }
 637→
 638→    fn parse_didl_lite(xml: &str) -> Option<TrackInfo> {
 639→        // Simple extraction from DIDL-Lite
 640→        let title = Self::extract_xml_value(xml, "dc:title")
 641→            .or_else(|| Self::extract_xml_value(xml, "title"))
 642→            .unwrap_or_default();
 643→
 644→        let artist = Self::extract_xml_value(xml, "upnp:artist")
 645→            .or_else(|| Self::extract_xml_value(xml, "dc:creator"))
 646→            .unwrap_or_default();
 647→
 648→        let album = Self::extract_xml_value(xml, "upnp:album").unwrap_or_default();
 649→
 650→        let album_art_uri = Self::extract_xml_value(xml, "upnp:albumArtURI");
 651→
 652→        let genre = Self::extract_xml_value(xml, "upnp:genre");
 653→
 654→        Some(TrackInfo {
 655→            title,
 656→            artist,
 657→            album,
 658→            album_art_uri,
 659→            genre,
 660→        })
 661→    }
