 754→    /// Send control command to a zone
 755→    pub async fn control(
 756→        &self,
 757→        uuid: &str,
 758→        action: &str,
 759→        value: Option<i32>,
 760→    ) -> anyhow::Result<()> {
 761→        let uuid = strip_openhome_prefix(uuid);
 762→        let location = {
 763→            let state = self.state.read().await;
 764→            state
 765→                .devices
 766→                .get(uuid)
 767→                .map(|d| d.location.clone())
 768→                .ok_or_else(|| anyhow::anyhow!("Device not found: {}", uuid))?
 769→        };
 770→
 771→        let base_url = Self::get_base_url(&location)?;
 772→        let transport_url = format!("{}/Transport", base_url);
 773→        let volume_url = format!("{}/Volume", base_url);
 774→
 775→        match action {
 776→            "play" => {
 777→                Self::soap_call(
 778→                    &self.http,
 779→                    &transport_url,
 780→                    "urn:av-openhome-org:service:Transport:1",
 781→                    "Play",
 782→                    "",
 783→                )
 784→                .await?;
 785→            }
 786→            "pause" => {
 787→                Self::soap_call(
 788→                    &self.http,
 789→                    &transport_url,
 790→                    "urn:av-openhome-org:service:Transport:1",
 791→                    "Pause",
 792→                    "",
 793→                )
 794→                .await?;
 795→            }
 796→            "play_pause" => {
 797→                let state = self.state.read().await;
 798→                let is_playing = state
 799→                    .devices
 800→                    .get(uuid)
 801→                    .map(|d| d.state == "playing")
 802→                    .unwrap_or(false);
 803→                drop(state);
 804→
 805→                let action = if is_playing { "Pause" } else { "Play" };
 806→                Self::soap_call(
 807→                    &self.http,
 808→                    &transport_url,
 809→                    "urn:av-openhome-org:service:Transport:1",
 810→                    action,
 811→                    "",
 812→                )
 813→                .await?;
 814→            }
 815→            "stop" => {
 816→                Self::soap_call(
 817→                    &self.http,
 818→                    &transport_url,
 819→                    "urn:av-openhome-org:service:Transport:1",
 820→                    "Stop",
 821→                    "",
 822→                )
 823→                .await?;
 824→            }
 825→            "next" => {
 826→                Self::soap_call(
 827→                    &self.http,
 828→                    &transport_url,
 829→                    "urn:av-openhome-org:service:Transport:1",
 830→                    "SkipNext",
 831→                    "",
 832→                )
 833→                .await?;
 834→            }
 835→            "previous" | "prev" => {
 836→                Self::soap_call(
 837→                    &self.http,
 838→                    &transport_url,
 839→                    "urn:av-openhome-org:service:Transport:1",
 840→                    "SkipPrevious",
 841→                    "",
 842→                )
 843→                .await?;
 844→            }
 845→            "vol_abs" | "volume" => {
 846→                let vol = value.unwrap_or(50).clamp(0, 100);
 847→                Self::soap_call(
 848→                    &self.http,
 849→                    &volume_url,
 850→                    "urn:av-openhome-org:service:Volume:1",
 851→                    "SetVolume",
 852→                    &format!("<Value>{}</Value>", vol),
 853→                )
 854→                .await?;
 855→
 856→                let mut state = self.state.write().await;
 857→                if let Some(device) = state.devices.get_mut(uuid) {
 858→                    device.volume = Some(vol);
 859→                }
 860→            }
 861→            "vol_rel" => {
 862→                let delta = value.unwrap_or(0);
 863→                let current = {
 864→                    let state = self.state.read().await;
 865→                    state.devices.get(uuid).and_then(|d| d.volume).unwrap_or(50)
 866→                };
 867→                let new_vol = (current + delta).clamp(0, 100);
 868→
 869→                Self::soap_call(
 870→                    &self.http,
 871→                    &volume_url,
 872→                    "urn:av-openhome-org:service:Volume:1",
 873→                    "SetVolume",
 874→                    &format!("<Value>{}</Value>", new_vol),
 875→                )
 876→                .await?;
 877→
 878→                let mut state = self.state.write().await;
 879→                if let Some(device) = state.devices.get_mut(uuid) {
 880→                    device.volume = Some(new_vol);
 881→                }
 882→            }
 883→            _ => {
 884→                anyhow::bail!("Unknown action: {}", action);
 885→            }
 886→        }
 887→
 888→        // Trigger immediate poll
 889→        let state = self.state.clone();
 890→        let bus = self.bus.clone();
 891→        let http = self.http.clone();
 892→        let uuid = uuid.to_string();
 893→        let location = location.clone();
 894→
 895→        tokio::spawn(async move {
 896→            tokio::time::sleep(Duration::from_millis(200)).await;
 897→            let _ = Self::poll_device(&state, &bus, &http, &uuid, &location).await;
 898→        });
 899→
 900→        Ok(())
 901→    }
