 903→    /// Fetch album art image
 904→    pub async fn get_image(&self, image_url: &str) -> anyhow::Result<ImageData> {
 905→        if !image_url.starts_with("http://") && !image_url.starts_with("https://") {
 906→            anyhow::bail!("Invalid image URL");
 907→        }
 908→
 909→        let response = self.http.get(image_url).send().await?;
 910→        let content_type = response
 911→            .headers()
 912→            .get(reqwest::header::CONTENT_TYPE)
 913→            .and_then(|v| v.to_str().ok())
 914→            .unwrap_or("image/jpeg")
 915→            .to_string();
 916→
 917→        let body = response.bytes().await?;
 918→
 919→        Ok(ImageData {
 920→            content_type,
 921→            data: body.to_vec(),
 922→        })
 923→    }
 924→}
