 933→/// Decode HTML entities
 934→fn html_decode(s: &str) -> String {
 935→    s.replace("&lt;", "<")
 936→        .replace("&gt;", ">")
 937→        .replace("&amp;", "&")
 938→        .replace("&quot;", "\"")
 939→        .replace("&apos;", "'")
 940→}
