 942→/// Convert an OpenHome device to a unified Zone representation
 943→fn openhome_device_to_zone(device: &OpenHomeDevice) -> Zone {
 944→    Zone {
 945→        zone_id: format!("openhome:{}", device.uuid),
 946→        zone_name: device.name.clone(),
 947→        state: PlaybackState::from(device.state.as_str()),
 948→        volume_control: device.volume.map(|v| {
 949→            // Calculate step from Characteristics: step = VolumeMax / VolumeSteps
 950→            // See: http://wiki.openhome.org/wiki/Av:Developer:VolumeService
 951→            let step = match (device.volume_max, device.volume_steps) {
 952→                (Some(max), Some(steps)) if steps > 0 => max as f32 / steps as f32,
 953→                _ => 1.0, // Default if Characteristics not available
 954→            };
 955→            BusVolumeControl {
 956→                value: v as f32,
 957→                min: 0.0,
 958→                max: device.volume_max.map(|m| m as f32).unwrap_or(100.0),
 959→                step,
 960→                is_muted: device.muted,
 961→                scale: crate::bus::VolumeScale::Percentage,
 962→                // Use prefixed output_id for consistent aggregator matching
 963→                output_id: Some(format!("openhome:{}", device.uuid)),
 964→            }
 965→        }),
 966→        now_playing: device.track_info.as_ref().map(|t| crate::bus::NowPlaying {
 967→            title: t.title.clone(),
 968→            artist: t.artist.clone(),
 969→            album: t.album.clone(),
 970→            image_key: t.album_art_uri.clone(),
 971→            seek_position: None,
 972→            duration: None,
 973→            metadata: None,
 974→        }),
 975→        source: "openhome".to_string(),
 976→        is_controllable: true,
 977→        is_seekable: false, // OpenHome seek support varies
 978→        last_updated: std::time::SystemTime::now()
 979→            .duration_since(std::time::UNIX_EPOCH)
 980→            .unwrap_or_default()
 981→            .as_millis() as u64,
 982→        is_play_allowed: device.state != "playing",
 983→        is_pause_allowed: device.state == "playing",
 984→        is_next_allowed: true,
 985→        is_previous_allowed: true,
 986→    }
 987→}
