 989→// AdapterLogic implementation for unified retry handling
 990→#[async_trait]
 991→impl AdapterLogic for OpenHomeAdapter {
 992→    fn prefix(&self) -> &'static str {
 993→        "openhome"
 994→    }
 995→
 996→    async fn run(&self, ctx: AdapterContext) -> Result<()> {
 997→        // Mark as running
 998→        {
 999→            let mut state = self.state.write().await;
1000→            state.running = true;
1001→        }
1002→
1003→        // Run discovery and poll loops concurrently with shutdown check
1004→        let discovery_state = self.state.clone();
1005→        let discovery_bus = self.bus.clone();
1006→        let discovery_http = self.http.clone();
1007→        let discovery_shutdown = ctx.shutdown.clone();
1008→
1009→        let poll_state = self.state.clone();
1010→        let poll_bus = self.bus.clone();
1011→        let poll_http = self.http.clone();
1012→        let poll_shutdown = ctx.shutdown.clone();
1013→
1014→        tokio::select! {
1015→            _ = ctx.shutdown.cancelled() => {
1016→                tracing::info!("OpenHome adapter received shutdown signal");
1017→            }
1018→            _ = Self::discovery_loop(discovery_state, discovery_bus, discovery_http, discovery_shutdown) => {
1019→                tracing::info!("OpenHome discovery loop ended");
1020→            }
1021→            _ = Self::poll_loop(poll_state, poll_bus, poll_http, poll_shutdown) => {
1022→                tracing::info!("OpenHome poll loop ended");
1023→            }
1024→        }
1025→
1026→        // Clean up state on exit
1027→        {
1028→            let mut state = self.state.write().await;
1029→            state.running = false;
1030→            state.devices.clear();
1031→        }
1032→
1033→        tracing::info!("OpenHome adapter stopped");
1034→        Ok(())
1035→    }
1036→
1037→    async fn handle_command(
1038→        &self,
1039→        zone_id: &str,
1040→        command: AdapterCommand,
1041→    ) -> Result<AdapterCommandResponse> {
1042→        // Strip prefix if present
1043→        let uuid = zone_id.strip_prefix("openhome:").unwrap_or(zone_id);
1044→
1045→        let result = match command {
1046→            AdapterCommand::Play => self.control(uuid, "play", None).await,
1047→            AdapterCommand::Pause => self.control(uuid, "pause", None).await,
1048→            AdapterCommand::PlayPause => self.control(uuid, "play_pause", None).await,
1049→            AdapterCommand::Stop => self.control(uuid, "stop", None).await,
1050→            AdapterCommand::Next => self.control(uuid, "next", None).await,
1051→            AdapterCommand::Previous => self.control(uuid, "previous", None).await,
1052→            AdapterCommand::VolumeAbsolute(v) => self.control(uuid, "vol_abs", Some(v)).await,
1053→            AdapterCommand::VolumeRelative(v) => self.control(uuid, "vol_rel", Some(v)).await,
1054→            AdapterCommand::Mute(_) => {
1055→                // OpenHome mute not directly supported via this adapter yet
1056→                return Ok(AdapterCommandResponse {
1057→                    success: false,
1058→                    error: Some("Mute not supported by OpenHome adapter".to_string()),
1059→                });
1060→            }
1061→        };
1062→
1063→        match result {
1064→            Ok(()) => Ok(AdapterCommandResponse {
1065→                success: true,
1066→                error: None,
1067→            }),
1068→            Err(e) => Ok(AdapterCommandResponse {
1069→                success: false,
1070→                error: Some(e.to_string()),
1071→            }),
1072→        }
1073→    }
1074→}
