 122→/// UPnP adapter for discovering and controlling DLNA Media Renderers
 123→#[derive(Clone)]
 124→pub struct UPnPAdapter {
 125→    state: Arc<RwLock<UPnPState>>,
 126→    bus: SharedBus,
 127→    http: Client,
 128→    /// Wrapped in RwLock to allow creating fresh token on restart
 129→    shutdown: Arc<RwLock<CancellationToken>>,
 130→}
 131→
 132→impl UPnPAdapter {
 133→    /// Create new UPnP adapter
 134→    pub fn new(bus: SharedBus) -> Self {
 135→        Self {
 136→            state: Arc::new(RwLock::new(UPnPState {
 137→                renderers: HashMap::new(),
 138→                running: false,
 139→            })),
 140→            bus,
 141→            http: Client::builder()
 142→                .timeout(SOAP_TIMEOUT)
 143→                .build()
 144→                .unwrap_or_default(),
 145→            shutdown: Arc::new(RwLock::new(CancellationToken::new())),
 146→        }
 147→    }
 148→
 149→    /// Start SSDP discovery (internal - use Startable trait)
 150→    async fn start_internal(&self) -> anyhow::Result<()> {
 151→        // Use write lock to atomically check and set running flag
 152→        // This prevents race conditions where multiple starts could pass the check
 153→        {
 154→            let mut state = self.state.write().await;
 155→            if state.running {
 156→                return Ok(());
 157→            }
 158→            state.running = true;
 159→        }
 160→
 161→        // Create fresh cancellation token for this run (previous token may be cancelled)
 162→        let shutdown = {
 163→            let mut token = self.shutdown.write().await;
 164→            *token = CancellationToken::new();
 165→            token.clone()
 166→        };
 167→
 168→        // Create AdapterHandle and spawn with retry
 169→        let adapter = self.clone();
 170→        let bus = self.bus.clone();
 171→
 172→        tokio::spawn(async move {
 173→            let handle = AdapterHandle::new(adapter, bus, shutdown);
 174→            handle.run_with_retry(RetryConfig::default()).await
 175→        });
 176→
 177→        tracing::info!("UPnP adapter started");
 178→        Ok(())
 179→    }
 180→
 181→    async fn discovery_loop(
 182→        state: Arc<RwLock<UPnPState>>,
 183→        bus: SharedBus,
 184→        http: Client,
 185→        shutdown: CancellationToken,
 186→    ) {
 187→        let mut search_interval = interval(SSDP_SEARCH_INTERVAL);
 188→
 189→        loop {
 190→            tokio::select! {
 191→                _ = shutdown.cancelled() => {
 192→                    tracing::info!("UPnP discovery loop shutting down");
 193→                    break;
 194→                }
 195→                _ = search_interval.tick() => {
 196→                    // Perform SSDP search
 197→                    if let Err(e) = Self::perform_search(&state, &bus, &http).await {
 198→                        tracing::warn!("SSDP search failed: {}", e);
 199→                    }
 200→
 201→                    // Cleanup stale renderers
 202→                    Self::cleanup_stale(&state, &bus).await;
 203→                }
 204→            }
 205→        }
 206→
 207→        tracing::info!("UPnP discovery loop stopped");
 208→    }
 209→
 210→    async fn perform_search(
 211→        state: &Arc<RwLock<UPnPState>>,
 212→        bus: &SharedBus,
 213→        http: &Client,
 214→    ) -> anyhow::Result<()> {
 215→        let urn: URN = MEDIA_RENDERER_URN.parse()?;
 216→        let search_target = SearchTarget::URN(urn);
 217→        let responses =
 218→            ssdp_client::search(&search_target, Duration::from_secs(3), 2, None).await?;
 219→
 220→        futures::pin_mut!(responses);
 221→
 222→        while let Some(response) = responses.next().await {
 223→            let response = match response {
 224→                Ok(r) => r,
 225→                Err(e) => {
 226→                    tracing::debug!("SSDP response error: {}", e);
 227→                    continue;
 228→                }
 229→            };
 230→
 231→            let location = response.location().to_string();
 232→            let usn = response.usn();
 233→
 234→            // Extract UUID from USN
 235→            let uuid = match usn.split("::").next() {
 236→                Some(s) if s.starts_with("uuid:") => s.trim_start_matches("uuid:").to_string(),
 237→                _ => continue,
 238→            };
 239→
 240→            // Update existing or add new
 241→            let mut s = state.write().await;
 242→            if let Some(renderer) = s.renderers.get_mut(&uuid) {
 243→                renderer.last_seen = std::time::Instant::now();
 244→                continue;
 245→            }
 246→
 247→            tracing::info!("Discovered UPnP MediaRenderer: {} at {}", uuid, location);
 248→
 249→            // New renderer
 250→            let renderer = UPnPRenderer {
 251→                uuid: uuid.clone(),
 252→                name: format!("Renderer {}", &uuid[..8.min(uuid.len())]),
 253→                manufacturer: None,
 254→                model: None,
 255→                location: location.clone(),
 256→                state: "stopped".to_string(),
 257→                volume: None,
 258→                muted: false,
 259→                last_seen: std::time::Instant::now(),
 260→                av_transport_url: None,
 261→                rendering_control_url: None,
 262→            };
 263→
 264→            s.renderers.insert(uuid.clone(), renderer);
 265→            drop(s);
 266→
 267→            // Fetch device description
 268→            let state_clone = state.clone();
 269→            let http_clone = http.clone();
 270→            let bus_clone = bus.clone();
 271→            let uuid_clone = uuid.clone();
 272→
 273→            tokio::spawn(async move {
 274→                if let Err(e) =
 275→                    Self::fetch_device_info(&state_clone, &http_clone, &uuid_clone, &location).await
 276→                {
 277→                    tracing::warn!("Failed to fetch device info for {}: {}", uuid_clone, e);
 278→                }
 279→                // Emit ZoneDiscovered with full zone info
 280→                let s = state_clone.read().await;
 281→                if let Some(renderer) = s.renderers.get(&uuid_clone) {
 282→                    let zone = upnp_renderer_to_zone(renderer);
 283→                    bus_clone.publish(BusEvent::ZoneDiscovered { zone });
 284→                }
 285→            });
 286→        }
 287→
 288→        Ok(())
 289→    }
 290→
 291→    async fn fetch_device_info(
 292→        state: &Arc<RwLock<UPnPState>>,
 293→        http: &Client,
 294→        uuid: &str,
 295→        location: &str,
 296→    ) -> anyhow::Result<()> {
 297→        let response = http.get(location).send().await?;
 298→        let xml = response.text().await?;
 299→
 300→        // Parse device description
 301→        #[derive(Deserialize)]
 302→        struct Root {
 303→            device: DeviceDesc,
 304→        }
 305→
 306→        #[derive(Deserialize)]
 307→        struct DeviceDesc {
 308→            #[serde(rename = "friendlyName")]
 309→            friendly_name: Option<String>,
 310→            manufacturer: Option<String>,
 311→            #[serde(rename = "modelName")]
 312→            model_name: Option<String>,
 313→            #[serde(rename = "serviceList")]
 314→            service_list: Option<ServiceList>,
 315→        }
 316→
 317→        #[derive(Deserialize)]
 318→        struct ServiceList {
 319→            service: Vec<ServiceDesc>,
 320→        }
 321→
 322→        #[derive(Deserialize)]
 323→        struct ServiceDesc {
 324→            #[serde(rename = "serviceType")]
 325→            service_type: String,
 326→            #[serde(rename = "controlURL")]
 327→            control_url: Option<String>,
 328→        }
 329→
 330→        let root: Root = xml_from_str(&xml)?;
 331→
 332→        // Get base URL
 333→        let base_url = Self::get_base_url(location)?;
 334→
 335→        let mut s = state.write().await;
 336→        if let Some(renderer) = s.renderers.get_mut(uuid) {
 337→            renderer.name = root
 338→                .device
 339→                .friendly_name
 340→                .unwrap_or_else(|| format!("Renderer {}", &uuid[..8.min(uuid.len())]));
 341→            renderer.manufacturer = root.device.manufacturer;
 342→            renderer.model = root.device.model_name;
 343→
 344→            // Extract service URLs
 345→            if let Some(services) = root.device.service_list {
 346→                for service in services.service {
 347→                    if service.service_type.contains("AVTransport") {
 348→                        if let Some(url) = service.control_url {
 349→                            renderer.av_transport_url = Some(format!("{}{}", base_url, url));
 350→                        }
 351→                    } else if service.service_type.contains("RenderingControl") {
 352→                        if let Some(url) = service.control_url {
 353→                            renderer.rendering_control_url = Some(format!("{}{}", base_url, url));
 354→                        }
 355→                    }
 356→                }
 357→            }
 358→
 359→            tracing::info!(
 360→                "Got UPnP device info: {} - {} {}",
 361→                renderer.name,
 362→                renderer.manufacturer.as_deref().unwrap_or("Unknown"),
 363→                renderer.model.as_deref().unwrap_or("")
 364→            );
 365→        }
 366→
 367→        Ok(())
 368→    }
