 370→    async fn cleanup_stale(state: &Arc<RwLock<UPnPState>>, bus: &SharedBus) {
 371→        let mut s = state.write().await;
 372→        let now = std::time::Instant::now();
 373→
 374→        let stale: Vec<String> = s
 375→            .renderers
 376→            .iter()
 377→            .filter(|(_, r)| now.duration_since(r.last_seen) > STALE_THRESHOLD)
 378→            .map(|(uuid, _)| uuid.clone())
 379→            .collect();
 380→
 381→        for uuid in stale {
 382→            tracing::info!("Removing stale UPnP renderer: {}", uuid);
 383→            s.renderers.remove(&uuid);
 384→            bus.publish(BusEvent::ZoneRemoved {
 385→                zone_id: PrefixedZoneId::upnp(&uuid),
 386→            });
 387→        }
 388→    }
 389→
 390→    async fn poll_loop(
 391→        state: Arc<RwLock<UPnPState>>,
 392→        bus: SharedBus,
 393→        http: Client,
 394→        shutdown: CancellationToken,
 395→    ) {
 396→        let mut poll_interval = interval(POLL_INTERVAL);
 397→
 398→        loop {
 399→            tokio::select! {
 400→                _ = shutdown.cancelled() => {
 401→                    tracing::info!("UPnP poll loop shutting down");
 402→                    break;
 403→                }
 404→                _ = poll_interval.tick() => {
 405→                    // Get list of renderers to poll
 406→                    let renderers: Vec<(String, Option<String>, Option<String>)> = {
 407→                        let s = state.read().await;
 408→                        s.renderers
 409→                            .iter()
 410→                            .map(|(uuid, r)| {
 411→                                (
 412→                                    uuid.clone(),
 413→                                    r.av_transport_url.clone(),
 414→                                    r.rendering_control_url.clone(),
 415→                                )
 416→                            })
 417→                            .collect()
 418→                    };
 419→
 420→                    for (uuid, av_url, rc_url) in renderers {
 421→                        if let Err(e) = Self::poll_renderer(
 422→                            &state,
 423→                            &bus,
 424→                            &http,
 425→                            &uuid,
 426→                            av_url.as_deref(),
 427→                            rc_url.as_deref(),
 428→                        )
 429→                        .await
 430→                        {
 431→                            tracing::debug!("Failed to poll {}: {}", uuid, e);
 432→                        }
 433→                    }
 434→                }
 435→            }
 436→        }
 437→
 438→        tracing::info!("UPnP poll loop stopped");
 439→    }
 440→
 441→    async fn poll_renderer(
 442→        state: &Arc<RwLock<UPnPState>>,
 443→        bus: &SharedBus,
 444→        http: &Client,
 445→        uuid: &str,
 446→        av_url: Option<&str>,
 447→        rc_url: Option<&str>,
 448→    ) -> anyhow::Result<()> {
 449→        // Poll transport state
 450→        if let Some(url) = av_url {
 451→            let transport_info = Self::soap_call(
 452→                http,
 453→                url,
 454→                AV_TRANSPORT_URN,
 455→                "GetTransportInfo",
 456→                "<InstanceID>0</InstanceID>",
 457→            )
 458→            .await;
 459→
 460→            if let Ok(response) = transport_info {
 461→                if let Some(new_state) = Self::extract_xml_value(&response, "CurrentTransportState")
 462→                {
 463→                    let new_state = match new_state.as_str() {
 464→                        "PLAYING" => "playing",
 465→                        "PAUSED_PLAYBACK" => "paused",
 466→                        "STOPPED" => "stopped",
 467→                        "TRANSITIONING" => "loading",
 468→                        _ => "stopped",
 469→                    }
 470→                    .to_string();
 471→
 472→                    let mut s = state.write().await;
 473→                    if let Some(renderer) = s.renderers.get_mut(uuid) {
 474→                        if renderer.state != new_state {
 475→                            renderer.state = new_state.clone();
 476→                            bus.publish(BusEvent::ZoneUpdated {
 477→                                zone_id: PrefixedZoneId::upnp(uuid),
 478→                                display_name: renderer.name.clone(),
 479→                                state: new_state,
 480→                            });
 481→                        }
 482→                    }
 483→                }
 484→            }
 485→        }
 486→
 487→        // Poll volume
 488→        if let Some(url) = rc_url {
 489→            let volume = Self::soap_call(
 490→                http,
 491→                url,
 492→                RENDERING_CONTROL_URN,
 493→                "GetVolume",
 494→                "<InstanceID>0</InstanceID><Channel>Master</Channel>",
 495→            )
 496→            .await;
 497→
 498→            if let Ok(response) = volume {
 499→                if let Some(vol_str) = Self::extract_xml_value(&response, "CurrentVolume") {
 500→                    if let Ok(vol) = vol_str.parse::<i32>() {
 501→                        let mut s = state.write().await;
 502→                        if let Some(renderer) = s.renderers.get_mut(uuid) {
 503→                            renderer.volume = Some(vol);
 504→                        }
 505→                    }
 506→                }
 507→            }
 508→
 509→            // Poll mute
 510→            let mute = Self::soap_call(
 511→                http,
 512→                url,
 513→                RENDERING_CONTROL_URN,
 514→                "GetMute",
 515→                "<InstanceID>0</InstanceID><Channel>Master</Channel>",
 516→            )
 517→            .await;
 518→
 519→            if let Ok(response) = mute {
 520→                if let Some(mute_str) = Self::extract_xml_value(&response, "CurrentMute") {
 521→                    let mut s = state.write().await;
 522→                    if let Some(renderer) = s.renderers.get_mut(uuid) {
 523→                        renderer.muted = mute_str == "1" || mute_str.eq_ignore_ascii_case("true");
 524→                    }
 525→                }
 526→            }
 527→        }
 528→
 529→        Ok(())
 530→    }
