 532→    fn get_base_url(location: &str) -> anyhow::Result<String> {
 533→        let url = url::Url::parse(location)?;
 534→        let port = url.port().map(|p| format!(":{}", p)).unwrap_or_default();
 535→        Ok(format!(
 536→            "{}://{}{}",
 537→            url.scheme(),
 538→            url.host_str().unwrap_or("localhost"),
 539→            port
 540→        ))
 541→    }
 542→
 543→    async fn soap_call(
 544→        http: &Client,
 545→        url: &str,
 546→        service_type: &str,
 547→        action: &str,
 548→        body_content: &str,
 549→    ) -> anyhow::Result<String> {
 550→        let soap_body = format!(
 551→            r#"<?xml version="1.0" encoding="utf-8"?>
 552→<s:Envelope xmlns:s="http://schemas.xmlsoap.org/soap/envelope/" s:encodingStyle="http://schemas.xmlsoap.org/soap/encoding/">
 553→  <s:Body>
 554→    <u:{action} xmlns:u="{service_type}">{body}</u:{action}>
 555→  </s:Body>
 556→</s:Envelope>"#,
 557→            action = action,
 558→            service_type = service_type,
 559→            body = body_content
 560→        );
 561→
 562→        let response = http
 563→            .post(url)
 564→            .header("Content-Type", "text/xml; charset=utf-8")
 565→            .header("SOAPAction", format!("\"{}#{}\"", service_type, action))
 566→            .body(soap_body)
 567→            .send()
 568→            .await?;
 569→
 570→        Ok(response.text().await?)
 571→    }
