 573→    /// Extract XML value, handling optional namespace prefixes (e.g., <u:Volume> or <Volume>)
 574→    fn extract_xml_value(xml: &str, tag: &str) -> Option<String> {
 575→        // Build regex pattern to match tag with optional namespace prefix and attributes
 576→        // Matches: <prefix:tag attr="...">value</prefix:tag> or <tag attr="...">value</tag>
 577→        let pattern = format!(
 578→            r"<(?:[^:>]+:)?{}\b[^>]*>([^<]*)</(?:[^:>]+:)?{}>",
 579→            regex::escape(tag),
 580→            regex::escape(tag)
 581→        );
 582→
 583→        let re = Regex::new(&pattern).ok()?;
 584→        re.captures(xml)
 585→            .and_then(|caps| caps.get(1))
 586→            .map(|m| m.as_str().to_string())
 587→    }
