 589→    /// Stop discovery (internal - use Startable trait)
 590→    async fn stop_internal(&self) {
 591→        // Cancel background tasks first
 592→        self.shutdown.read().await.cancel();
 593→
 594→        let mut state = self.state.write().await;
 595→        state.running = false;
 596→        state.renderers.clear();
 597→        tracing::info!("UPnP adapter stopped");
 598→    }
