 618→    /// Get all discovered renderers as zones
 619→    pub async fn get_zones(&self) -> Vec<UPnPZone> {
 620→        let state = self.state.read().await;
 621→        state
 622→            .renderers
 623→            .values()
 624→            .map(|r| {
 625→                let device_name = match (&r.manufacturer, &r.model) {
 626→                    (Some(m), Some(model)) => Some(format!("{} {}", m, model)),
 627→                    (Some(m), None) => Some(m.clone()),
 628→                    _ => None,
 629→                };
 630→
 631→                UPnPZone {
 632→                    zone_id: r.uuid.clone(),
 633→                    zone_name: r.name.clone(),
 634→                    state: r.state.clone(),
 635→                    output_count: 1,
 636→                    output_name: r.name.clone(),
 637→                    device_name,
 638→                    volume_control: r.volume.map(|_| VolumeControl {
 639→                        vol_type: "number".to_string(),
 640→                        min: 0,
 641→                        max: 100,
 642→                        is_muted: r.muted,
 643→                    }),
 644→                    // Pure UPnP doesn't support these
 645→                    unsupported: vec![
 646→                        "next".to_string(),
 647→                        "previous".to_string(),
 648→                        "track_metadata".to_string(),
 649→                        "album_art".to_string(),
 650→                    ],
 651→                }
 652→            })
