 662→    /// Get specific renderer by UUID
 663→    pub async fn get_renderer(&self, uuid: &str) -> Option<UPnPRenderer> {
 664→        let uuid = strip_upnp_prefix(uuid);
 665→        let state = self.state.read().await;
 666→        state.renderers.get(uuid).cloned()
 667→    }
 668→
 669→    /// Get now playing info for a renderer
 670→    pub async fn get_now_playing(&self, uuid: &str) -> Option<UPnPNowPlaying> {
 671→        let uuid = strip_upnp_prefix(uuid);
 672→        let state = self.state.read().await;
 673→        let renderer = state.renderers.get(uuid)?;
 674→
 675→        // Pure UPnP doesn't provide track metadata
 676→        Some(UPnPNowPlaying {
 677→            zone_id: uuid.to_string(),
 678→            line1: renderer.name.clone(),
 679→            line2: String::new(),
 680→            line3: String::new(),
 681→            is_playing: renderer.state == "playing",
 682→            volume: renderer.volume,
 683→            volume_min: 0,
 684→            volume_max: 100,
 685→            seek_position: None,
 686→            length: None,
 687→            image_key: None,
 688→        })
 689→    }
 690→
 691→    /// Send control command to a renderer
 692→    pub async fn control(
 693→        &self,
 694→        uuid: &str,
 695→        action: &str,
 696→        value: Option<i32>,
 697→    ) -> anyhow::Result<()> {
 698→        let uuid = strip_upnp_prefix(uuid);
 699→        let (av_url, rc_url) = {
 700→            let state = self.state.read().await;
 701→            let renderer = state
 702→                .renderers
 703→                .get(uuid)
 704→                .ok_or_else(|| anyhow::anyhow!("Renderer not found: {}", uuid))?;
 705→            (
 706→                renderer.av_transport_url.clone(),
 707→                renderer.rendering_control_url.clone(),
 708→            )
 709→        };
 710→
 711→        match action {
 712→            "play" => {
 713→                let url = av_url
 714→                    .as_ref()
 715→                    .ok_or_else(|| anyhow::anyhow!("No AVTransport URL"))?;
 716→                Self::soap_call(
 717→                    &self.http,
 718→                    url,
 719→                    AV_TRANSPORT_URN,
 720→                    "Play",
 721→                    "<InstanceID>0</InstanceID><Speed>1</Speed>",
 722→                )
 723→                .await?;
 724→            }
 725→            "pause" => {
 726→                let url = av_url
 727→                    .as_ref()
 728→                    .ok_or_else(|| anyhow::anyhow!("No AVTransport URL"))?;
 729→                Self::soap_call(
 730→                    &self.http,
 731→                    url,
 732→                    AV_TRANSPORT_URN,
 733→                    "Pause",
 734→                    "<InstanceID>0</InstanceID>",
 735→                )
 736→                .await?;
 737→            }
 738→            "play_pause" => {
 739→                let url = av_url
 740→                    .as_ref()
 741→                    .ok_or_else(|| anyhow::anyhow!("No AVTransport URL"))?;
 742→                let is_playing = {
 743→                    let state = self.state.read().await;
 744→                    state
 745→                        .renderers
 746→                        .get(uuid)
 747→                        .map(|r| r.state == "playing")
 748→                        .unwrap_or(false)
 749→                };
 750→
 751→                if is_playing {
 752→                    Self::soap_call(
 753→                        &self.http,
 754→                        url,
 755→                        AV_TRANSPORT_URN,
 756→                        "Pause",
 757→                        "<InstanceID>0</InstanceID>",
 758→                    )
 759→                    .await?;
 760→                } else {
 761→                    Self::soap_call(
 762→                        &self.http,
 763→                        url,
 764→                        AV_TRANSPORT_URN,
 765→                        "Play",
 766→                        "<InstanceID>0</InstanceID><Speed>1</Speed>",
 767→                    )
 768→                    .await?;
 769→                }
 770→            }
 771→            "stop" => {
 772→                let url = av_url
 773→                    .as_ref()
 774→                    .ok_or_else(|| anyhow::anyhow!("No AVTransport URL"))?;
 775→                Self::soap_call(
 776→                    &self.http,
 777→                    url,
 778→                    AV_TRANSPORT_URN,
 779→                    "Stop",
 780→                    "<InstanceID>0</InstanceID>",
 781→                )
 782→                .await?;
 783→            }
 784→            "next" => {
 785→                anyhow::bail!("Next track not supported by pure UPnP renderers");
 786→            }
 787→            "previous" | "prev" => {
 788→                anyhow::bail!("Previous track not supported by pure UPnP renderers");
 789→            }
 790→            "vol_abs" | "volume" => {
 791→                let url = rc_url
 792→                    .as_ref()
 793→                    .ok_or_else(|| anyhow::anyhow!("No RenderingControl URL"))?;
 794→                let vol = value.unwrap_or(50).clamp(0, 100);
 795→                Self::soap_call(
 796→                    &self.http,
 797→                    url,
 798→                    RENDERING_CONTROL_URN,
 799→                    "SetVolume",
 800→                    &format!("<InstanceID>0</InstanceID><Channel>Master</Channel><DesiredVolume>{}</DesiredVolume>", vol),
 801→                ).await?;
 802→
 803→                let mut state = self.state.write().await;
 804→                if let Some(renderer) = state.renderers.get_mut(uuid) {
 805→                    renderer.volume = Some(vol);
 806→                }
 807→            }
 808→            "vol_rel" => {
 809→                let url = rc_url
 810→                    .as_ref()
 811→                    .ok_or_else(|| anyhow::anyhow!("No RenderingControl URL"))?;
 812→                let delta = value.unwrap_or(0);
 813→                let current = {
 814→                    let state = self.state.read().await;
 815→                    state
 816→                        .renderers
 817→                        .get(uuid)
 818→                        .and_then(|r| r.volume)
 819→                        .unwrap_or(50)
 820→                };
 821→                let new_vol = (current + delta).clamp(0, 100);
 822→
 823→                Self::soap_call(
 824→                    &self.http,
 825→                    url,
 826→                    RENDERING_CONTROL_URN,
 827→                    "SetVolume",
 828→                    &format!("<InstanceID>0</InstanceID><Channel>Master</Channel><DesiredVolume>{}</DesiredVolume>", new_vol),
 829→                ).await?;
 830→
 831→                let mut state = self.state.write().await;
 832→                if let Some(renderer) = state.renderers.get_mut(uuid) {
 833→                    renderer.volume = Some(new_vol);
 834→                }
 835→            }
 836→            "mute" => {
 837→                let url = rc_url
 838→                    .as_ref()
 839→                    .ok_or_else(|| anyhow::anyhow!("No RenderingControl URL"))?;
 840→                let mute = value.map(|v| v != 0).unwrap_or(true);
 841→                Self::soap_call(
 842→                    &self.http,
 843→                    url,
 844→                    RENDERING_CONTROL_URN,
 845→                    "SetMute",
 846→                    &format!("<InstanceID>0</InstanceID><Channel>Master</Channel><DesiredMute>{}</DesiredMute>", if mute { "1" } else { "0" }),
 847→                ).await?;
 848→
 849→                let mut state = self.state.write().await;
 850→                if let Some(renderer) = state.renderers.get_mut(uuid) {
 851→                    renderer.muted = mute;
 852→                }
 853→            }
 854→            _ => {
 855→                anyhow::bail!("Unknown action: {}", action);
 856→            }
 857→        }
 858→
 859→        // Trigger immediate poll
 860→        let state = self.state.clone();
 861→        let bus = self.bus.clone();
 862→        let http = self.http.clone();
 863→        let uuid = uuid.to_string();
 864→
 865→        tokio::spawn(async move {
 866→            tokio::time::sleep(Duration::from_millis(200)).await;
 867→            let _ = Self::poll_renderer(
 868→                &state,
 869→                &bus,
 870→                &http,
 871→                &uuid,
 872→                av_url.as_deref(),
 873→                rc_url.as_deref(),
 874→            )
 875→            .await;
 876→        });
 877→
 878→        Ok(())
 879→    }
 880→}
 881→
 882→/// Convert a UPnP renderer to a unified Zone representation
 883→fn upnp_renderer_to_zone(renderer: &UPnPRenderer) -> Zone {
 884→    Zone {
 885→        zone_id: format!("upnp:{}", renderer.uuid),
 886→        zone_name: renderer.name.clone(),
 887→        state: PlaybackState::from(renderer.state.as_str()),
 888→        volume_control: renderer.volume.map(|v| BusVolumeControl {
 889→            value: v as f32,
 890→            min: 0.0,
 891→            max: 100.0,
 892→            step: 1.0,
 893→            is_muted: renderer.muted,
 894→            scale: crate::bus::VolumeScale::Percentage,
 895→            // Use prefixed output_id for consistent aggregator matching
 896→            output_id: Some(format!("upnp:{}", renderer.uuid)),
 897→        }),
 898→        now_playing: None, // UPnP track info would need separate DIDL-Lite parsing
 899→        source: "upnp".to_string(),
 900→        is_controllable: renderer.av_transport_url.is_some(),
 901→        is_seekable: false, // Pure UPnP seek support is limited
 902→        last_updated: std::time::SystemTime::now()
 903→            .duration_since(std::time::UNIX_EPOCH)
 904→            .unwrap_or_default()
 905→            .as_millis() as u64,
 906→        is_play_allowed: renderer.state != "playing",
 907→        is_pause_allowed: renderer.state == "playing",
 908→        is_next_allowed: false,
 909→        is_previous_allowed: false,
 910→    }
 911→}
 912→
 913→#[async_trait]
 914→impl AdapterLogic for UPnPAdapter {
 915→    fn prefix(&self) -> &'static str {
 916→        "upnp"
 917→    }
 918→
 919→    async fn run(&self, ctx: AdapterContext) -> Result<()> {
 920→        // Mark as running
 921→        {
 922→            let mut state = self.state.write().await;
 923→            state.running = true;
 924→        }
 925→
 926→        // Run discovery and poll loops concurrently with shutdown check
 927→        let state = self.state.clone();
 928→        let bus = ctx.bus.clone();
 929→        let http = self.http.clone();
 930→        let shutdown = ctx.shutdown.clone();
 931→
 932→        let discovery_state = state.clone();
 933→        let discovery_bus = bus.clone();
 934→        let discovery_http = http.clone();
 935→        let discovery_shutdown = shutdown.clone();
 936→
 937→        let poll_state = state.clone();
 938→        let poll_bus = bus.clone();
 939→        let poll_http = http.clone();
 940→        let poll_shutdown = shutdown.clone();
 941→
 942→        tokio::select! {
 943→            _ = shutdown.cancelled() => {
 944→                tracing::info!("UPnP adapter shutting down");
 945→            }
 946→            _ = async {
 947→                tokio::join!(
 948→                    Self::discovery_loop(discovery_state, discovery_bus, discovery_http, discovery_shutdown),
 949→                    Self::poll_loop(poll_state, poll_bus, poll_http, poll_shutdown)
 950→                );
 951→            } => {}
 952→        }
 953→
 954→        // Cleanup state on exit
 955→        {
 956→            let mut state = self.state.write().await;
 957→            state.running = false;
 958→            state.renderers.clear();
 959→        }
 960→
 961→        Ok(())
 962→    }
 963→
 964→    async fn handle_command(
 965→        &self,
 966→        zone_id: &str,
 967→        command: AdapterCommand,
 968→    ) -> Result<AdapterCommandResponse> {
 969→        // Strip "upnp:" prefix if present (bus/aggregator uses prefixed IDs)
 970→        let uuid = zone_id.strip_prefix("upnp:").unwrap_or(zone_id);
 971→
 972→        let result = match command {
 973→            AdapterCommand::Play => self.control(uuid, "play", None).await,
 974→            AdapterCommand::Pause => self.control(uuid, "pause", None).await,
 975→            AdapterCommand::PlayPause => self.control(uuid, "play_pause", None).await,
 976→            AdapterCommand::Stop => self.control(uuid, "stop", None).await,
 977→            AdapterCommand::Next => {
 978→                return Ok(AdapterCommandResponse {
 979→                    success: false,
 980→                    error: Some("Next track not supported by pure UPnP renderers".to_string()),
 981→                });
 982→            }
 983→            AdapterCommand::Previous => {
 984→                return Ok(AdapterCommandResponse {
 985→                    success: false,
 986→                    error: Some("Previous track not supported by pure UPnP renderers".to_string()),
 987→                });
 988→            }
 989→            AdapterCommand::VolumeAbsolute(vol) => self.control(uuid, "vol_abs", Some(vol)).await,
 990→            AdapterCommand::VolumeRelative(delta) => {
 991→                self.control(uuid, "vol_rel", Some(delta)).await
 992→            }
 993→            AdapterCommand::Mute(mute) => {
 994→                self.control(uuid, "mute", Some(if mute { 1 } else { 0 }))
 995→                    .await
 996→            }
 997→        };
 998→
 999→        match result {
1000→            Ok(()) => Ok(AdapterCommandResponse {
1001→                success: true,
1002→                error: None,
1003→            }),
1004→            Err(e) => Ok(AdapterCommandResponse {
1005→                success: false,
1006→                error: Some(e.to_string()),
1007→            }),
1008→        }
1009→    }
1010→}
