 41→/// Zones listing page component.
 42→#[component]
 43→pub fn Zones() -> Element {
 44→    let sse = use_sse();
 45→
 46→    // Load zones resource
 47→    let mut zones = use_resource(|| async {
 48→        crate::app::api::fetch_json::<ZonesResponse>("/zones")
 49→            .await
 50→            .ok()
 51→    });
 52→
 53→    // Now playing state (populated after zones load and refreshed on SSE events)
 54→    let mut now_playing = use_signal(HashMap::<String, NowPlaying>::new);
 55→
 56→    // Track zones list for now_playing refresh
 57→    let zones_list_signal = use_memo(move || {
 58→        zones
 59→            .read()
 60→            .clone()
 61→            .flatten()
 62→            .map(|r| r.zones)
 63→            .unwrap_or_default()
 64→    });
 65→
 66→    // Load now playing for each zone when zones change
 67→    use_effect(move || {
 68→        let zone_list = zones_list_signal();
 69→        if !zone_list.is_empty() {
 70→            spawn(async move {
 71→                let np_map = fetch_all_now_playing(&zone_list).await;
 72→                now_playing.set(np_map);
 73→            });
 74→        }
 75→    });
 76→
 77→    // Refresh on SSE events
 78→    use_effect(move || {
 79→        let _ = (sse.event_count)();
 80→        let event = (sse.last_event)();
 81→
 82→        // Refresh zones list on structural changes
 83→        if matches!(
 84→            event.as_ref(),
 85→            Some(
 86→                SseEvent::ZoneUpdated { .. }
 87→                    | SseEvent::ZoneRemoved { .. }
 88→                    | SseEvent::RoonConnected
 89→                    | SseEvent::RoonDisconnected
 90→                    | SseEvent::LmsConnected
 91→                    | SseEvent::LmsDisconnected
 92→            )
 93→        ) {
 94→            zones.restart();
 95→        }
 96→
 97→        // Refresh now_playing on playback/volume changes
 98→        // Use selective per-zone fetching to avoid race conditions when multiple
 99→        // zones update rapidly (fixes issue #109 - wrong album art display)
100→        if let Some(ref evt) = event {
101→            match evt {
102→                // Zone-scoped events: fetch only the specific zone that changed
103→                // ZoneUpdated includes state changes (play/pause) that affect is_playing
104→                SseEvent::NowPlayingChanged { .. } | SseEvent::ZoneUpdated { .. } => {
105→                    if let Some(zone_id) = evt.zone_id() {
106→                        let zone_id = zone_id.to_string();
107→                        spawn(async move {
108→                            if let Some(np) = fetch_zone_now_playing(&zone_id).await {
109→                                now_playing.with_mut(|map| {
110→                                    map.insert(zone_id, np);
111→                                });
112→                            }
113→                        });
114→                    }
115→                }
116→                // Volume/LMS events: fetch all zones and merge atomically
117→                // (output_id/player_id don't map directly to zone_id)
118→                SseEvent::VolumeChanged { .. } | SseEvent::LmsPlayerStateChanged { .. } => {
119→                    let zone_list = zones_list_signal();
120→                    if !zone_list.is_empty() {
121→                        spawn(async move {
122→                            let np_map = fetch_all_now_playing(&zone_list).await;
123→                            now_playing.with_mut(|map| {
124→                                for (k, v) in np_map {
125→                                    map.insert(k, v);
126→                                }
127→                            });
128→                        });
129→                    }
130→                }
131→                // SeekPositionChanged doesn't affect track/artist/album art - no fetch needed
132→                _ => {}
133→            }
134→        }
135→    });
136→
137→    // Control handler
138→    let control = move |(zone_id, action): (String, String)| {
139→        spawn(async move {
140→            let req = ControlRequest {
141→                zone_id,
142→                action,
143→                value: None,
144→            };
145→            if let Err(e) = crate::app::api::post_json_no_response("/control", &req).await {
146→                #[cfg(target_arch = "wasm32")]
147→                web_sys::console::warn_1(&format!("Control request failed: {e}").into());
148→                #[cfg(not(target_arch = "wasm32"))]
149→                tracing::warn!("Control request failed: {e}");
150→            }
151→        });
152→    };
153→
154→    // HQPlayer state (shared across all HQP zones)
155→    let mut hqp_profiles = use_signal(Vec::<HqpProfile>::new);
156→    let mut hqp_matrix = use_signal(|| None::<HqpMatrixProfilesResponse>);
157→    let mut hqp_error = use_signal(|| None::<String>);
158→
159→    // Check if any zone has HQP
160→    let has_any_hqp = use_memo(move || {
161→        zones_list_signal().iter().any(|z| {
162→            z.dsp
163→                .as_ref()
164→                .map(|d| d.r#type.as_deref() == Some("hqplayer"))
165→                .unwrap_or(false)
166→        })
167→    });
168→
169→    // Fetch HQP profiles/matrix when there are HQP zones
170→    use_effect(move || {
171→        if has_any_hqp() {
172→            spawn(async move {
173→                if let Ok(profiles) =
174→                    crate::app::api::fetch_json::<Vec<HqpProfile>>("/hqplayer/profiles").await
175→                {
176→                    hqp_profiles.set(profiles);
177→                }
178→                if let Ok(matrix) = crate::app::api::fetch_json::<HqpMatrixProfilesResponse>(
179→                    "/hqplayer/matrix/profiles",
180→                )
181→                .await
182→                {
183→                    hqp_matrix.set(Some(matrix));
184→                }
185→            });
186→        }
187→    });
188→
189→    // Load profile handler
190→    let load_profile = move |profile: String| {
191→        hqp_error.set(None);
192→        spawn(async move {
193→            #[derive(serde::Serialize)]
194→            struct ProfileRequest {
195→                profile: String,
196→            }
197→            let req = ProfileRequest { profile };
198→            if let Err(e) = crate::app::api::post_json_no_response("/hqplayer/profile", &req).await
199→            {
200→                hqp_error.set(Some(format!("Profile load failed: {e}")));
201→            }
202→        });
203→    };
204→
205→    // Set matrix profile handler
206→    let set_matrix = move |profile_idx: u32| {
207→        hqp_error.set(None);
208→        spawn(async move {
209→            #[derive(serde::Serialize)]
210→            struct MatrixRequest {
211→                profile: u32,
212→            }
213→            let req = MatrixRequest {
214→                profile: profile_idx,
215→            };
216→            match crate::app::api::post_json_no_response("/hqplayer/matrix/profile", &req).await {
217→                Ok(_) => {
218→                    // Refresh matrix after change
219→                    if let Ok(matrix) = crate::app::api::fetch_json::<HqpMatrixProfilesResponse>(
220→                        "/hqplayer/matrix/profiles",
221→                    )
222→                    .await
223→                    {
224→                        hqp_matrix.set(Some(matrix));
225→                    }
226→                }
227→                Err(e) => {
228→                    hqp_error.set(Some(format!("Matrix profile failed: {e}")));
229→                }
230→            }
231→        });
232→    };
233→
234→    let is_loading = zones.read().is_none();
235→    let zones_list = zones
236→        .read()
237→        .clone()
238→        .flatten()
239→        .map(|r| r.zones)
240→        .unwrap_or_default();
241→    let np_map = now_playing();
242→
243→    let profiles = hqp_profiles();
244→    let matrix = hqp_matrix();
245→
246→    // Group zones by source protocol
247→    let grouped_zones: Vec<(String, Vec<Zone>)> = {
248→        let mut groups: std::collections::HashMap<String, Vec<Zone>> =
249→            std::collections::HashMap::new();
250→        for zone in zones_list.iter() {
251→            let source = zone.source.clone().unwrap_or_else(|| "Other".to_string());
252→            groups.entry(source).or_default().push(zone.clone());
253→        }
254→        // Sort zones within each group by name for stable ordering
255→        for zones in groups.values_mut() {
256→            zones.sort_by(|a, b| a.zone_name.cmp(&b.zone_name));
257→        }
258→        // Sort groups in a sensible order: Roon, LMS, OpenHome, UPnP, then others
259→        let priority = |s: &str| -> i32 {
260→            match s.to_lowercase().as_str() {
261→                "roon" => 0,
262→                "lms" => 1,
263→                "openhome" => 2,
264→                "upnp" => 3,
265→                _ => 4,
266→            }
267→        };
268→        let mut result: Vec<_> = groups.into_iter().collect();
269→        result.sort_by(|a, b| priority(&a.0).cmp(&priority(&b.0)));
270→        result
271→    };
272→
273→    let content = if is_loading {
274→        rsx! {
275→            div { class: "card p-6", aria_busy: "true", "Loading zones..." }
276→        }
277→    } else if zones_list.is_empty() {
278→        rsx! {
279→            div { class: "card p-6", "No zones available. Check that adapters are connected." }
280→        }
281→    } else {
282→        rsx! {
283→            for (source, group_zones) in grouped_zones {
284→                div { class: "mb-8",
285→                    h3 { class: "text-lg font-semibold mb-4 text-muted", "{source}" }
286→                    div { class: "grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-3",
287→                        for zone in group_zones {
288→                            ZoneCard {
289→                                key: "{zone.zone_id}",
290→                                zone: zone.clone(),
291→                                now_playing: np_map.get(&zone.zone_id).cloned(),
292→                                hqp_profiles: profiles.clone(),
293→                                hqp_matrix: matrix.clone(),
294→                                on_control: control,
295→                                on_load_profile: load_profile,
296→                                on_set_matrix: set_matrix,
297→                            }
298→                        }
299→                    }
300→                }
301→            }
302→        }
303→    };
304→
305→    rsx! {
306→        Layout {
307→            title: "Zones".to_string(),
308→            nav_active: "zones".to_string(),
309→
310→            h1 { class: "text-2xl font-bold mb-6", "Zones" }
311→
312→            // HQP error display
313→            if let Some(error) = hqp_error() {
314→                ErrorAlert {
315→                    message: error,
316→                    on_dismiss: move |_| hqp_error.set(None),
317→                }
318→            }
319→
320→            section { id: "zones",
321→                {content}
322→            }
323→        }
324→    }
325→}
