327→/// Zone card component
328→#[component]
329→fn ZoneCard(
330→    zone: Zone,
331→    now_playing: Option<NowPlaying>,
332→    hqp_profiles: Vec<HqpProfile>,
333→    hqp_matrix: Option<HqpMatrixProfilesResponse>,
334→    on_control: EventHandler<(String, String)>,
335→    on_load_profile: EventHandler<String>,
336→    on_set_matrix: EventHandler<u32>,
337→) -> Element {
338→    let zone_id = zone.zone_id.clone();
339→    let zone_id_prev = zone_id.clone();
340→    let zone_id_play = zone_id.clone();
341→    let zone_id_next = zone_id.clone();
342→    let zone_id_vol_down = zone_id.clone();
343→    let zone_id_vol_up = zone_id.clone();
344→
345→    let np = now_playing.as_ref();
346→    let is_playing = np.map(|n| n.is_playing).unwrap_or(false);
347→
348→    let has_hqp = zone
349→        .dsp
350→        .as_ref()
351→        .map(|d| d.r#type.as_deref() == Some("hqplayer"))
352→        .unwrap_or(false);
353→
354→    // Extract volume info for component
355→    let volume = np.and_then(|n| n.volume);
356→    let volume_type = np.and_then(|n| n.volume_type.clone());
357→    let volume_step = np.and_then(|n| n.volume_step);
358→
359→    // Album art URL with cache-busting image_key
360→    let base_image_url = np.and_then(|n| n.image_url.clone()).unwrap_or_default();
361→    let image_key = np.and_then(|n| n.image_key.clone());
362→    let image_url = if let Some(key) = image_key {
363→        let sep = if base_image_url.contains('?') {
364→            "&"
365→        } else {
366→            "?"
367→        };
368→        format!("{}{}k={}", base_image_url, sep, key)
369→    } else {
370→        base_image_url
371→    };
372→    let has_image = !image_url.is_empty();
373→
374→    // Now playing display
375→    let (track, artist) = np
376→        .map(|n| {
377→            if n.line1.as_deref().unwrap_or("Idle") != "Idle" {
378→                (
379→                    n.line1.clone().unwrap_or_default(),
380→                    n.line2.clone().unwrap_or_default(),
381→                )
382→            } else {
383→                (String::new(), String::new())
384→            }
385→        })
386→        .unwrap_or_default();
387→
388→    // HQP matrix info
389→    let has_matrix = hqp_matrix
390→        .as_ref()
391→        .map(|m| !m.profiles.is_empty())
392→        .unwrap_or(false);
393→    let matrix_profiles = hqp_matrix
394→        .as_ref()
395→        .map(|m| m.profiles.clone())
396→        .unwrap_or_default();
397→    let matrix_current = hqp_matrix.as_ref().and_then(|m| m.current);
398→
399→    rsx! {
400→        article { class: "zone-card",
401→            // Main content with album art and info (same layout as zone detail)
402→            div { class: "flex gap-3 sm:gap-5 items-start overflow-hidden",
403→                // Album art (smaller on mobile, 96px on larger screens)
404→                if has_image {
405→                    img {
406→                        src: "{image_url}",
407→                        alt: "Album art",
408→                        class: "w-16 h-16 sm:w-24 sm:h-24 object-cover rounded-lg bg-elevated flex-shrink-0"
409→                    }
410→                } else {
411→                    div { class: "w-16 h-16 sm:w-24 sm:h-24 rounded-lg bg-elevated flex items-center justify-center text-muted text-2xl sm:text-3xl flex-shrink-0",
412→                        "♪"
413→                    }
414→                }
415→
416→                // Zone info
417→                div { class: "flex-1 min-w-0",
418→                    // Header with zone name and HQP badge
419→                    h3 { class: "flex items-center gap-2 mb-2 text-base font-semibold",
420→                        span { class: "truncate", "{zone.zone_name}" }
421→                        if has_hqp {
422→                            span { class: "badge badge-primary", "HQP" }
423→                        }
424→                    }
425→
426→                    // Now playing info
427→                    if !track.is_empty() {
428→                        p { class: "font-medium text-sm truncate mb-1", "{track}" }
429→                        p { class: "text-sm text-muted truncate", "{artist}" }
430→                    } else {
431→                        p { class: "text-sm text-muted", "Nothing playing" }
432→                    }
433→                }
434→            }
435→
436→            // HQP controls (for HQP zones only)
437→            if has_hqp && (!hqp_profiles.is_empty() || has_matrix) {
438→                HqpControlsCompact {
439→                    profiles: hqp_profiles,
440→                    matrix_profiles: matrix_profiles,
441→                    active_matrix: matrix_current,
442→                    on_profile_select: on_load_profile,
443→                    on_matrix_select: on_set_matrix,
444→                }
445→            }
446→
447→            // Transport controls
448→            div { class: "flex flex-wrap items-center gap-2 mt-4",
449→                button {
450→                    class: "btn btn-ghost",
451→                    "aria-label": "Previous track",
452→                    onclick: move |_| on_control.call((zone_id_prev.clone(), "previous".to_string())),
453→                    svg { class: "w-5 h-5", fill: "currentColor", view_box: "0 0 24 24",
454→                        path { d: "M6 6h2v12H6zm3.5 6l8.5 6V6z" }
455→                    }
456→                }
457→                button {
458→                    class: "btn btn-primary",
459→                    "aria-label": if is_playing { "Pause" } else { "Play" },
460→                    onclick: move |_| on_control.call((zone_id_play.clone(), "play_pause".to_string())),
461→                    if is_playing {
462→                        svg { class: "w-5 h-5", fill: "currentColor", view_box: "0 0 24 24",
463→                            path { d: "M6 19h4V5H6v14zm8-14v14h4V5h-4z" }
464→                        }
465→                    } else {
466→                        svg { class: "w-5 h-5", fill: "currentColor", view_box: "0 0 24 24",
467→                            path { d: "M8 5v14l11-7z" }
468→                        }
469→                    }
470→                }
471→                button {
472→                    class: "btn btn-ghost",
473→                    "aria-label": "Next track",
474→                    onclick: move |_| on_control.call((zone_id_next.clone(), "next".to_string())),
475→                    svg { class: "w-5 h-5", fill: "currentColor", view_box: "0 0 24 24",
476→                        path { d: "M6 18l8.5-6L6 6v12zM16 6v12h2V6h-2z" }
477→                    }
478→                }
479→
480→                VolumeControlsCompact {
481→                    volume: volume,
482→                    volume_type: volume_type,
483→                    volume_step: volume_step,
484→                    on_vol_down: move |_| on_control.call((zone_id_vol_down.clone(), "vol_down".to_string())),
485→                    on_vol_up: move |_| on_control.call((zone_id_vol_up.clone(), "vol_up".to_string())),
486→                }
487→            }
488→        }
489→    }
490→}
