 1→//! Event bus for inter-component communication
 2→//!
 3→//! Uses tokio::sync::broadcast for pub/sub pattern.
 4→//! Events are typed and can carry payloads.
 5→
 6→use std::sync::Arc;
 7→use tokio::sync::broadcast;
 8→
 9→pub mod events;
10→pub use events::*;
11→
12→/// Event bus handle for publishing and subscribing
13→#[derive(Clone)]
14→pub struct EventBus {
15→    sender: broadcast::Sender<BusEvent>,
16→}
17→
18→impl Default for EventBus {
19→    fn default() -> Self {
20→        Self::new(256)
21→    }
22→}
23→
24→impl EventBus {
25→    /// Create a new event bus with specified capacity
26→    pub fn new(capacity: usize) -> Self {
27→        let (sender, _) = broadcast::channel(capacity);
28→        Self { sender }
29→    }
30→
31→    /// Publish an event to all subscribers
32→    pub fn publish(&self, event: BusEvent) {
33→        // Ignore send errors (no subscribers)
34→        let _ = self.sender.send(event);
35→    }
36→
37→    /// Subscribe to all events
38→    pub fn subscribe(&self) -> broadcast::Receiver<BusEvent> {
39→        self.sender.subscribe()
40→    }
41→
42→    /// Get the number of current subscribers
43→    pub fn subscriber_count(&self) -> usize {
44→        self.sender.receiver_count()
45→    }
46→}
47→
48→/// Shared event bus wrapped in Arc for thread-safe sharing
49→pub type SharedBus = Arc<EventBus>;
50→
51→/// Create a new shared event bus
52→pub fn create_bus() -> SharedBus {
53→    Arc::new(EventBus::default())
54→}
55→
56→#[cfg(test)]
57→mod tests {
58→    use super::*;
59→
60→    #[tokio::test]
61→    async fn test_pubsub() {
62→        let bus = create_bus();
63→        let mut rx = bus.subscribe();
64→
65→        bus.publish(BusEvent::RoonConnected {
66→            core_name: "Test Core".to_string(),
67→            version: "1.0".to_string(),
68→        });
69→
70→        let event = rx.recv().await.unwrap();
71→        match event {
72→            BusEvent::RoonConnected { core_name, .. } => {
73→                assert_eq!(core_name, "Test Core");
74→            }
75→            _ => panic!("Wrong event type"),
76→        }
77→    }
78→
79→    #[tokio::test]
80→    async fn test_multiple_subscribers() {
81→        let bus = create_bus();
82→        let mut rx1 = bus.subscribe();
83→        let mut rx2 = bus.subscribe();
84→
85→        bus.publish(BusEvent::RoonDisconnected);
86→
87→        assert!(matches!(
88→            rx1.recv().await.unwrap(),
89→            BusEvent::RoonDisconnected
90→        ));
91→        assert!(matches!(
92→            rx2.recv().await.unwrap(),
93→            BusEvent::RoonDisconnected
94→        ));
95→    }
96→}
