133→#[test]
134→fn clamp_value_exactly_at_min_boundary() {
135→    assert_eq!(clamp(-64.0, -64.0, 0.0), -64.0);
136→    assert_eq!(clamp(0.0, 0.0, 100.0), 0.0);
137→}
