145→#[test]
146→fn clamp_value_in_middle_of_range() {
147→    assert_eq!(clamp(-32.0, -64.0, 0.0), -32.0);
148→    assert_eq!(clamp(50.0, 0.0, 100.0), 50.0);
149→}
