153→// =============================================================================
154→
155→#[test]
156→fn relative_step_clamped_prevents_wild_jumps() {
157→    // Even if someone sends +50, it should be clamped to MAX_RELATIVE_STEP (10)
158→    let max_step = 10.0;
159→    assert_eq!(clamp(50.0, -max_step, max_step), max_step);
160→    assert_eq!(clamp(-50.0, -max_step, max_step), -max_step);
161→}
