567→        "play_pause" | "playpause" => "play_pause",
568→        "next" => "next",
569→        "previous" | "prev" => "previous",
570→        "stop" => "stop",
571→        "vol_up" | "volume_up" => {
572→            // Use provided value, or look up zone's actual step from aggregator
573→            let step = match value.and_then(|v| v.as_f64()) {
