576→            };
577→            state
578→                .roon
579→                .change_volume(zone_id, step, true)
580→                .await
581→                .map_err(|e| {
582→                    (
583→                        StatusCode::INTERNAL_SERVER_ERROR,
584→                        Json(serde_json::json!({"error": e.to_string()})),
585→                    )
586→                })?;
587→            return Ok(Json(serde_json::json!({"ok": true})));
588→        }
589→        "vol_down" | "volume_down" => {
590→            // Use provided value, or look up zone's actual step from aggregator
591→            let step = match value.and_then(|v| v.as_f64()) {
592→                Some(v) => v as f32,
593→                None => get_zone_step(state, &format!("roon:{}", zone_id)).await,
594→            };
595→            state
596→                .roon
597→                .change_volume(zone_id, -step, true)
598→                .await
599→                .map_err(|e| {
600→                    (
601→                        StatusCode::INTERNAL_SERVER_ERROR,
602→                        Json(serde_json::json!({"error": e.to_string()})),
603→                    )
604→                })?;
605→            return Ok(Json(serde_json::json!({"ok": true})));
606→        }
607→        "vol_abs" | "volume" => {
608→            // Use as_f64() which handles both JSON integers and floats
609→            // (as_i64() returns None for floats like 75.0, causing fallback to 50)
610→            let vol = value.and_then(|v| v.as_f64()).unwrap_or(50.0) as f32;
611→            state
612→                .roon
613→                .change_volume(zone_id, vol, false)
614→                .await
615→                .map_err(|e| {
616→                    (
617→                        StatusCode::INTERNAL_SERVER_ERROR,
618→                        Json(serde_json::json!({"error": e.to_string()})),
619→                    )
620→                })?;
621→            return Ok(Json(serde_json::json!({"ok": true})));
622→        }
623→        _ => {
624→            return Err((
625→                StatusCode::BAD_REQUEST,
626→                Json(serde_json::json!({"error": format!("Unknown action: {}", action)})),
627→            ));
628→        }
629→    };
630→
631→    match state.roon.control(zone_id, roon_action).await {
632→        Ok(()) => Ok(Json(serde_json::json!({"ok": true}))),
633→        Err(e) => Err((
634→            StatusCode::INTERNAL_SERVER_ERROR,
635→            Json(serde_json::json!({"error": e.to_string()})),
636→        )),
637→    }
638→}
